import QuestionCard from './components/QuestionCard';
import AnalyticsDashboard from './components/AnalyticsDashboard';
import ProjectList from './components/ProjectList';
import { generateExam } from './services/geminiService';
import { saveProject, getAllProjects, deleteProject } from './services/storageService';
import { Stethoscope, Loader2, Key, ChevronDown, ChevronUp, Download, ArrowRight, AlertTriangle, History, CheckCheck, BarChart2, Layout, ArrowLeft, SignalHigh, SignalMedium, SignalLow, Layers, Hash, Printer } from 'lucide-react';
import { useReactToPrint } from 'react-to-print';

function App() {
  // --- Global State ---
  const [projects, setProjects] = useState<Project[]>([]);
  const [activeProject, setActiveProject] = useState<Project | null>(null);
  const [loadingProjects, setLoadingProjects] = useState(true);

  // --- UI State (Local to session) ---
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<'exam' | 'analytics'>('exam');

  // --- Initialization ---
  useEffect(() => {
    loadProjects();
  }, []);

  const loadProjects = async () => {
    const loadedProjects = await getAllProjects();
    setProjects(loadedProjects);
    setLoadingProjects(false);
  };

  const handleCreateProject = async (name: string, description: string, blueprint: BlueprintSection[], referenceTotal: number) => {
    const newProject: Project = {
        id: crypto.randomUUID(),
        name,
        description,
        lastModified: new Date().toISOString(),
        referenceTotalQuestions: referenceTotal,
        learningObjectivesFiles: [],
        blueprint: blueprint,
        examHistory: [],
        activeExam: {
            questions: [],
            userAnswers: {},
            status: 'active',
            configOpen: true,
            questionCount: 10,
            difficulty: 'standard'
        }
    };
    await saveProject(newProject);
    setProjects(prev => [newProject, ...prev]);
    setActiveProject(newProject);
  };

  const handleDeleteProject = async (id: string) => {
    await deleteProject(id);
    setProjects(prev => prev.filter(p => p.id !== id));
    if (activeProject?.id === id) setActiveProject(null);
  };

  const updateActiveProject = useCallback(async (updatedProject: Project) => {
    setActiveProject(updatedProject);
    setProjects(prev => prev.map(p => p.id === updatedProject.id ? updatedProject : p));
    await saveProject(updatedProject);
  }, []);

  // --- Project Specific Handlers ---

  const handleLoFilesChange = (files: UploadedFile[]) => {
    if (!activeProject) return;
    updateActiveProject({ ...activeProject, learningObjectivesFiles: files });
  };

  // Handle uploading files to a specific bucket/section
  const handleSectionFilesChange = (sectionId: string, files: UploadedFile[]) => {
    if (!activeProject) return;
    const updatedBlueprint = activeProject.blueprint.map(section => 
        section.id === sectionId ? { ...section, files } : section
    );
    updateActiveProject({ ...activeProject, blueprint: updatedBlueprint });
  };

  const handleQuestionCountChange = (count: number) => {
      if (!activeProject) return;
      updateActiveProject({
          ...activeProject,
          activeExam: { ...activeProject.activeExam, questionCount: count }
      });
  };

  const handleDifficultyChange = (level: DifficultyLevel) => {
    if (!activeProject) return;
    updateActiveProject({
        ...activeProject,
        activeExam: { ...activeProject.activeExam, difficulty: level }
    });
  };

  const handleConfigToggle = () => {
      if (!activeProject) return;
      updateActiveProject({
          ...activeProject,
          activeExam: { ...activeProject.activeExam, configOpen: !activeProject.activeExam.configOpen }
      });
  };

  const handleGenerate = async () => {
    if (!activeProject) return;

    // Validate that at least some content exists
    const hasLOs = activeProject.learningObjectivesFiles.length > 0;
    const hasContent = activeProject.blueprint.some(s => s.files.length > 0);

    if (!hasLOs && !hasContent) {
      setError("Please upload at least one file (Learning Objectives or Content in a Section).");
      return;
    }

    setLoading(true);
    setError(null);

    const resetExamState = {
        ...activeProject.activeExam,
        questions: [],
        userAnswers: {},
        status: 'active' as const,
        configOpen: false
    };
    setActiveProject({ ...activeProject, activeExam: resetExamState });

    try {
      const generatedQuestions = await generateExam(
          activeProject.learningObjectivesFiles, 
          activeProject.blueprint, 
          activeProject.activeExam.questionCount,
          activeProject.activeExam.difficulty || 'standard',
          activeProject.referenceTotalQuestions || 40 // Pass the reference total
      );

      const newExamState = {
          ...resetExamState,
          questions: generatedQuestions
      };

      updateActiveProject({ ...activeProject, activeExam: newExamState });
      setActiveTab('exam');
    } catch (err: any) {
      setError(err.message || "Failed to generate exam. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const handleOptionSelect = (questionId: number, option: string) => {
    if (!activeProject) return;
    const updatedAnswers = {
        ...activeProject.activeExam.userAnswers,
        [questionId]: option
    };
    updateActiveProject({
        ...activeProject,
        activeExam: { ...activeProject.activeExam, userAnswers: updatedAnswers }
    });
  };

  const handleUpdateQuestion = (updatedQuestion: ExamQuestion) => {
    if (!activeProject) return;
    const updatedQuestions = activeProject.activeExam.questions.map(q => 
        q.id === updatedQuestion.id ? updatedQuestion : q
    );
    updateActiveProject({
        ...activeProject,
        activeExam: { ...activeProject.activeExam, questions: updatedQuestions }
    });
  };

  const calculateScore = () => {
    if (!activeProject) return 0;
    let score = 0;
    activeProject.activeExam.questions.forEach(q => {
        if (activeProject.activeExam.userAnswers[q.id] === q.correctAnswer) {
            score++;
        }
    });
    return score;
  };

  const handleFinishExam = () => {
    if (!activeProject || activeProject.activeExam.questions.length === 0) return;
    const { questions, userAnswers } = activeProject.activeExam;

    if (Object.keys(userAnswers).length < questions.length) {
        if (!window.confirm(`You have answered ${Object.keys(userAnswers).length} out of ${questions.length} questions. Are you sure you want to submit?`)) {
            return;
        }
    }

    const finalScore = calculateScore();
    const attempt: ExamAttempt = {
        id: crypto.randomUUID(),
        date: new Date().toISOString(),
        score: finalScore,
        totalQuestions: questions.length,
        answers: { ...userAnswers },
        questions: [ ...questions ]
    };

    updateActiveProject({
        ...activeProject,
        examHistory: [...activeProject.examHistory, attempt],
        activeExam: { ...activeProject.activeExam, status: 'completed' }
    });

    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handlePrint = () => {
    window.print();
  };

  const handleDownload = () => {
    if (!activeProject) return;
    const { questions, userAnswers } = activeProject.activeExam;
    const content = questions.map((q, i) => `
Q${i+1}. ${q.vignette}
${q.leadIn}
A. ${q.options.A}
B. ${q.options.B}
C. ${q.options.C}
D. ${q.options.D}

User Answer: ${userAnswers[q.id] || "Skipped"}
Correct: ${q.correctAnswer}
Explanation: ${q.explanation}
Metadata: [${q.metadata.cognitiveLevel}, ${q.metadata.cluster}]
`).join('\n---\n');

    const blob = new Blob([content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${activeProject.name.replace(/\s+/g, '_')}_Exam_${new Date().toISOString().slice(0,10)}.txt`;
    a.click();
    URL.revokeObjectURL(url);
  };

  if (loadingProjects) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50">
        <Loader2 className="w-8 h-8 text-blue-600 animate-spin" />
      </div>
    );
  }

  // --- VIEW: PROJECT LIST ---
  if (!activeProject) {
      return (
          <div className="min-h-screen bg-slate-50">
             <header className="bg-white border-b border-slate-200 shadow-sm">
                <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
                    <div className="flex items-center space-x-3">
                        <div className="bg-blue-600 p-2 rounded-lg">
                            <Stethoscope className="w-5 h-5 text-white" />
                        </div>
                        <h1 className="text-xl font-bold text-slate-900 tracking-tight">MedExam Generator</h1>
                    </div>
                </div>
            </header>
            <ProjectList 
                projects={projects} 
                onSelectProject={setActiveProject}
                onCreateProject={handleCreateProject}
                onDeleteProject={handleDeleteProject}
            />
          </div>
      );
  }

  // --- VIEW: PROJECT WORKSPACE ---
  const { activeExam, learningObjectivesFiles, blueprint, examHistory } = activeProject;
  const currentDifficulty = activeExam.difficulty || 'standard';

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col print:bg-white">
      {/* Header - Hidden in Print */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-20 shadow-sm print:hidden">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-4">
             <button 
                onClick={() => setActiveProject(null)}
                className="p-2 -ml-2 text-slate-500 hover:text-blue-600 hover:bg-slate-100 rounded-lg transition-colors"
                title="Back to Projects"
             >
                 <ArrowLeft className="w-5 h-5" />
             </button>
             <div className="h-6 w-px bg-slate-200 mx-1"></div>
             <div>
                <h1 className="text-lg font-bold text-slate-900 tracking-tight leading-tight">{activeProject.name}</h1>
                <p className="text-xs text-slate-500 hidden sm:block">Project Workspace</p>
             </div>
          </div>

          <div className="flex items-center gap-2">
            <nav className="flex items-center p-1 bg-slate-100 rounded-lg mr-2">
                <button 
                    onClick={() => setActiveTab('exam')}
                    className={`flex items-center gap-2 px-3 py-1.5 text-sm font-medium rounded-md transition-all ${activeTab === 'exam' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                >
                    <Layout className="w-4 h-4" /> <span className="hidden sm:inline">Exam</span>
                </button>
                <button 
                    onClick={() => setActiveTab('analytics')}
                    className={`flex items-center gap-2 px-3 py-1.5 text-sm font-medium rounded-md transition-all ${activeTab === 'analytics' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                >
                    <BarChart2 className="w-4 h-4" /> <span className="hidden sm:inline">Progress</span>
                </button>
            </nav>
          </div>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 py-8 w-full flex-grow print:max-w-none print:p-0">

        {activeTab === 'exam' && (
            <div className="flex items-center gap-2 mb-4 text-xs text-slate-500 justify-end print:hidden">
                <History className="w-3 h-3" />
                <span>Auto-saved</span>
            </div>
        )}

        {/* ANALYTICS TAB */}
        {activeTab === 'analytics' && (
            <div className="animate-fadeIn print:hidden">
                <h2 className="text-2xl font-bold text-slate-900 mb-6">Performance Analytics: {activeProject.name}</h2>
                <AnalyticsDashboard history={examHistory} />
            </div>
        )}

        {/* EXAM TAB */}
        {activeTab === 'exam' && (
        <>
            {/* Configuration Panel - Hidden in Print */}
            <div className={`bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden mb-8 transition-all duration-300 print:hidden ${!activeExam.configOpen && activeExam.questions.length > 0 ? 'opacity-80 hover:opacity-100' : ''}`}>
            <div 
                className="px-6 py-4 bg-slate-50 border-b border-slate-200 flex items-center justify-between cursor-pointer"
                onClick={handleConfigToggle}
            >
                <h2 className="font-semibold text-slate-900 flex items-center gap-2">
                    <Key className="w-4 h-4 text-slate-500" />
                    Generator Configuration
                </h2>
                {activeExam.configOpen ? <ChevronUp className="w-4 h-4 text-slate-500"/> : <ChevronDown className="w-4 h-4 text-slate-500"/>}
            </div>

            {activeExam.configOpen && (
                <div className="p-6 space-y-8 animate-fadeIn">

                    {/* GLOBAL LEARNING OBJECTIVES */}
                    <div className="bg-slate-50 p-4 rounded-lg border border-slate-200">
                         <div className="flex items-center gap-2 mb-4">
                            <span className="flex items-center justify-center w-6 h-6 rounded-full bg-blue-100 text-blue-700 text-xs font-bold">1</span>
                            <h3 className="font-semibold text-slate-900">Learning Objectives (Global)</h3>
                        </div>
                        <FileUpload 
                            id="lo-upload"
                            files={learningObjectivesFiles} 
                            onFilesChanged={handleLoFilesChange} 
                            title="Weekly LOs (XLSX, PDF, Doc)"
                            description="Upload the master list of Learning Objectives"
                            className="bg-white"
                        />
                    </div>

                    {/* BLUEPRINT SECTIONS */}
                    <div>
                        <div className="flex items-center gap-2 mb-4">
                            <span className="flex items-center justify-center w-6 h-6 rounded-full bg-blue-100 text-blue-700 text-xs font-bold">2</span>
                            <h3 className="font-semibold text-slate-900">Content Breakdown</h3>
                        </div>

                        <div className="grid grid-cols-1 gap-6">
                            {blueprint.map((section) => (
                                <div key={section.id} className="border border-slate-200 rounded-lg p-4 relative">
                                    <div className="absolute top-0 right-0 bg-slate-100 px-3 py-1 text-xs font-bold text-slate-600 rounded-bl-lg border-l border-b border-slate-200 flex items-center gap-1">
                                        <Hash className="w-3 h-3 text-slate-400" />
                                        {section.questionCount} Questions (Ref)
                                    </div>
                                    <h4 className="font-bold text-slate-800 mb-1 flex items-center gap-2">
                                        <Layers className="w-4 h-4 text-slate-400" /> {section.title}
                                    </h4>
                                    <p className="text-xs text-slate-500 mb-4">{section.description}</p>

                                    <FileUpload 
                                        id={`section-${section.id}`}
                                        files={section.files} 
                                        onFilesChanged={(files) => handleSectionFilesChange(section.id, files)}
                                        title={`Upload Material for ${section.title}`}
                                        description="Lecture slides, notes, or transcripts specific to this section"
                                    />
                                </div>
                            ))}
                        </div>
                    </div>

                    <hr className="border-slate-100" />

                    {/* Settings Grid */}
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        {/* Difficulty Selector */}
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-2">
                                Difficulty Level
                            </label>
                            <div className="grid grid-cols-3 gap-2 bg-slate-50 p-1.5 rounded-lg border border-slate-200">
                                <button
                                    onClick={() => handleDifficultyChange('standard')}
                                    className={`flex items-center justify-center gap-1.5 py-2 px-3 rounded-md text-sm font-medium transition-all ${currentDifficulty === 'standard' ? 'bg-white text-blue-600 shadow-sm border border-slate-100' : 'text-slate-500 hover:text-slate-700 hover:bg-slate-200/50'}`}
                                >
                                    <SignalLow className="w-4 h-4" /> Standard
                                </button>
                                <button
                                    onClick={() => handleDifficultyChange('hard')}
                                    className={`flex items-center justify-center gap-1.5 py-2 px-3 rounded-md text-sm font-medium transition-all ${currentDifficulty === 'hard' ? 'bg-white text-yellow-600 shadow-sm border border-slate-100' : 'text-slate-500 hover:text-slate-700 hover:bg-slate-200/50'}`}
                                >
                                    <SignalMedium className="w-4 h-4" /> Hard
                                </button>
                                <button
                                    onClick={() => handleDifficultyChange('expert')}
                                    className={`flex items-center justify-center gap-1.5 py-2 px-3 rounded-md text-sm font-medium transition-all ${currentDifficulty === 'expert' ? 'bg-white text-red-600 shadow-sm border border-slate-100' : 'text-slate-500 hover:text-slate-700 hover:bg-slate-200/50'}`}
                                >
                                    <SignalHigh className="w-4 h-4" /> Expert
                                </button>
                            </div>
                        </div>

                        {/* Question Count */}
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-2">
                                Generate Questions (Mock Exam Size)
                            </label>
                            <div className="flex items-center gap-4 bg-slate-50 p-3 rounded-lg border border-slate-200 h-[50px]">
                                <input 
                                    type="range" 
                                    min="5" 
                                    max="50" 
                                    step="1"
                                    value={activeExam.questionCount}
                                    onChange={(e) => handleQuestionCountChange(parseInt(e.target.value))}
                                    className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-blue-600"
                                />
                                <span className="font-mono text-lg font-bold w-12 text-center text-blue-600 bg-white rounded border border-slate-200 px-2 py-0.5 text-sm">
                                    {activeExam.questionCount}
                                </span>
                            </div>
                        </div>
                    </div>

                    {/* Generate Button */}
                    <button
                        onClick={handleGenerate}
                        disabled={loading}
                        className={`w-full py-4 px-6 rounded-xl font-bold text-lg shadow-sm transition-all flex items-center justify-center space-x-2
                        ${loading
                            ? 'bg-slate-100 text-slate-400 cursor-not-allowed border border-slate-200' 
                            : 'bg-blue-600 text-white hover:bg-blue-700 hover:shadow-lg hover:-translate-y-0.5'
                        }`}
                    >
                        {loading ? (
                        <>
                            <Loader2 className="w-6 h-6 animate-spin" />
                            <span>Analyzing & Generating...</span>
                        </>
                        ) : (
                        <>
                            <span>Generate Practice Exam</span>
                            <ArrowRight className="w-5 h-5" />
                        </>
                        )}
                    </button>

                    {error && (
                        <div className="p-4 bg-red-50 text-red-700 text-sm rounded-lg border border-red-200 flex items-start gap-2">
                            <AlertTriangle className="w-5 h-5 flex-shrink-0 mt-0.5" />
                            <div>
                                <div className="font-bold">Generation Failed</div>
                                <div>{error}</div>
                            </div>
                        </div>
                    )}
                </div>
            )}
            </div>

            {/* Results Header with Score */}
            {activeExam.questions.length > 0 && (
            <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4 mb-6 print:mb-8">
                 <div className="print:hidden">
                    <h3 className="text-2xl font-bold text-slate-900 flex items-center gap-2">
                        {activeExam.status === 'completed' ? 'Exam Results' : 'Active Exam'}
                        {activeExam.difficulty === 'expert' && <span className="bg-red-100 text-red-700 text-xs px-2 py-0.5 rounded-full font-bold uppercase">Expert</span>}
                        {activeExam.difficulty === 'hard' && <span className="bg-yellow-100 text-yellow-700 text-xs px-2 py-0.5 rounded-full font-bold uppercase">Hard</span>}
                    </h3>
                    <p className="text-slate-500 mt-1">
                        {activeExam.status === 'completed' 
                            ? `You scored ${calculateScore()} out of ${activeExam.questions.length} (${Math.round((calculateScore()/activeExam.questions.length)*100)}%)` 
                            : `${Object.keys(activeExam.userAnswers).length} of ${activeExam.questions.length} questions answered`}
                    </p>
                 </div>

                 {/* Print Header */}
                 <div className="hidden print:block w-full text-center mb-8 border-b-2 border-black pb-4">
                     <h1 className="text-3xl font-bold text-black">{activeProject.name} - Practice Exam</h1>
                     <p className="text-gray-600 mt-2">Questions: {activeExam.questions.length} | Difficulty: {activeExam.difficulty?.toUpperCase() || 'STANDARD'}</p>
                 </div>

                 <div className="flex items-center gap-3 print:hidden">
                    <button
                        onClick={handlePrint}
                        className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-slate-700 bg-white border border-slate-200 hover:bg-slate-50 rounded-lg transition-colors shadow-sm"
                    >
                        <Printer className="w-4 h-4" /> Print
                    </button>
                    {activeExam.status === 'completed' && (
                        <button
                        onClick={handleDownload}
                        className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-slate-700 bg-white border border-slate-200 hover:bg-slate-50 rounded-lg transition-colors shadow-sm"
                        >
                            <Download className="w-4 h-4" /> Export
                        </button>
                     )}

                     {activeExam.status === 'active' && (
                         <button
                         onClick={handleFinishExam}
                         className="flex items-center gap-2 px-6 py-2 text-sm font-bold text-white bg-green-600 hover:bg-green-700 rounded-lg transition-colors shadow-sm hover:shadow"
                         >
                             <CheckCheck className="w-4 h-4" /> Finish Exam
                         </button>
                     )}
                 </div>
            </div>
            )}

            {/* Question List */}
            {activeExam.questions.length > 0 && (
            <div className="space-y-6 animate-slideUp print:space-y-8">
                {activeExam.questions.map((q, index) => (
                <QuestionCard 
                    key={q.id || index} 
                    question={q} 
                    index={index} 
                    selectedOption={activeExam.userAnswers[q.id] || null}
                    onSelectOption={(opt) => handleOptionSelect(q.id, opt)}
                    onUpdateQuestion={handleUpdateQuestion}
                    isSubmitted={activeExam.status === 'completed'}
                />
                ))}

                {/* Answer Key for Print */}
                <div className="hidden print:block break-before-page">
                    <h2 className="text-2xl font-bold mb-6 border-b-2 border-black pb-2">Answer Key & Explanations</h2>
                    <div className="space-y-6">
                        {activeExam.questions.map((q, i) => (
                            <div key={i} className="mb-4">
                                <div className="font-bold text-lg mb-1">Question {i+1}: <span className="text-black">{q.correctAnswer}</span></div>
                                <p className="text-sm text-gray-700">{q.explanation}</p>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Bottom Finish Button (if long exam) */}
                {activeExam.questions.length > 3 && activeExam.status === 'active' && (
                    <div className="flex justify-center pt-8 pb-12 print:hidden">
                         <button
                         onClick={handleFinishExam}
                         className="flex items-center gap-2 px-8 py-4 text-lg font-bold text-white bg-green-600 hover:bg-green-700 rounded-xl transition-all shadow-md hover:shadow-lg hover:-translate-y-0.5"
                         >
                             <CheckCheck className="w-5 h-5" /> Finish & Submit Exam
                         </button>
                    </div>
                )}
            </div>
            )}

            {/* Empty State */}
            {!loading && activeExam.questions.length === 0 && !activeExam.configOpen && (
                <div className="text-center py-12 bg-slate-50 rounded-xl border border-dashed border-slate-300 print:hidden">
                    <p className="text-slate-500 font-medium">Exam generation complete or pending. <button onClick={handleConfigToggle} className="text-blue-600 hover:underline">Open configuration</button> to start.</p>
                </div>
            )}
        </>
        )}
      </main>
    </div>
  );
}

export default App;

import React, { useState } from 'react';
import { ExamQuestion } from '../types';
import { CheckCircle2, XCircle, BrainCircuit, Tag, BookOpen, Edit2, Save, X } from 'lucide-react';

interface QuestionCardProps {
  question: ExamQuestion;
  index: number;
  selectedOption: string | null;
  onSelectOption: (option: string) => void;
  onUpdateQuestion: (question: ExamQuestion) => void;
  isSubmitted: boolean;
}

const QuestionCard: React.FC<QuestionCardProps> = ({ 
  question, 
  index, 
  selectedOption, 
  onSelectOption, 
  onUpdateQuestion,
  isSubmitted 
}) => {
  const [isEditing, setIsEditing] = useState(false);
  const [editedQuestion, setEditedQuestion] = useState<ExamQuestion>(question);

  const getOptionStyle = (optionKey: string) => {
    if (!isSubmitted) {
      return selectedOption === optionKey
        ? 'bg-blue-50 border-blue-500 ring-1 ring-blue-500 print:border-slate-800 print:ring-0 print:bg-transparent'
        : 'bg-white hover:bg-slate-50 border-slate-200';
    }

    // Submitted Mode
    if (optionKey === question.correctAnswer) {
      return 'bg-green-50 border-green-500 ring-1 ring-green-500';
    }
    if (selectedOption === optionKey && selectedOption !== question.correctAnswer) {
      return 'bg-red-50 border-red-500';
    }
    return 'bg-white opacity-50 border-slate-200';
  };

  const handleSave = () => {
      onUpdateQuestion(editedQuestion);
      setIsEditing(false);
  };

  const handleCancel = () => {
      setEditedQuestion(question);
      setIsEditing(false);
  };

  if (isEditing) {
      return (
        <div className="bg-white rounded-xl shadow-lg border-2 border-blue-400 overflow-hidden mb-6 p-6 space-y-4 animate-fadeIn">
            <div className="flex justify-between items-center mb-2">
                <h3 className="font-bold text-blue-800">Editing Question {index + 1}</h3>
                <div className="flex gap-2">
                    <button onClick={handleCancel} className="p-2 text-slate-500 hover:bg-slate-100 rounded-full"><X className="w-5 h-5"/></button>
                    <button onClick={handleSave} className="flex items-center gap-1 px-3 py-1.5 bg-blue-600 text-white rounded-lg hover:bg-blue-700 text-sm font-bold"><Save className="w-4 h-4"/> Save</button>
                </div>
            </div>

            <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Vignette</label>
                <textarea 
                    className="w-full p-2 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                    rows={4}
                    value={editedQuestion.vignette}
                    onChange={(e) => setEditedQuestion({...editedQuestion, vignette: e.target.value})}
                />
            </div>

            <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Lead In Question</label>
                <input 
                    className="w-full p-2 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                    value={editedQuestion.leadIn}
                    onChange={(e) => setEditedQuestion({...editedQuestion, leadIn: e.target.value})}
                />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {(['A', 'B', 'C', 'D'] as const).map(opt => (
                    <div key={opt}>
                        <div className="flex items-center justify-between mb-1">
                             <label className="block text-xs font-bold text-slate-500 uppercase">Option {opt}</label>
                             <input 
                                type="radio" 
                                name={`correct-${question.id}`}
                                checked={editedQuestion.correctAnswer === opt}
                                onChange={() => setEditedQuestion({...editedQuestion, correctAnswer: opt})}
                                className="w-4 h-4 text-blue-600 accent-blue-600 cursor-pointer"
                                title="Mark as correct answer"
                             />
                        </div>
                        <input 
                            className={`w-full p-2 border rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none ${editedQuestion.correctAnswer === opt ? 'border-green-500 bg-green-50' : 'border-slate-300'}`}
                            value={editedQuestion.options[opt]}
                            onChange={(e) => setEditedQuestion({
                                ...editedQuestion, 
                                options: { ...editedQuestion.options, [opt]: e.target.value }
                            })}
                        />
                    </div>
                ))}
            </div>

            <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Explanation</label>
                <textarea 
                    className="w-full p-2 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                    rows={3}
                    value={editedQuestion.explanation}
                    onChange={(e) => setEditedQuestion({...editedQuestion, explanation: e.target.value})}
                />
            </div>
        </div>
      );
  }

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden mb-6 print:shadow-none print:border-black print:mb-8 print:break-inside-avoid">
      {/* Header Metadata - Simplified for Print */}
      <div className="bg-slate-50 px-6 py-3 border-b border-slate-200 flex flex-wrap gap-3 items-center text-xs text-slate-600 print:bg-transparent print:border-b print:border-gray-300">
        <span className="font-bold text-slate-900 text-sm">Q{index + 1}</span>
        <div className="flex items-center gap-1 print:hidden">
          <BookOpen className="w-3 h-3" /> Week {question.metadata.week}
        </div>
        <div className="flex items-center gap-1 print:hidden">
          <BrainCircuit className="w-3 h-3" /> Level {question.metadata.cognitiveLevel}
        </div>
        <div className="flex items-center gap-1 print:hidden">
          <Tag className="w-3 h-3" /> {question.metadata.cluster}
        </div>
        <span className="bg-slate-200 px-2 py-0.5 rounded-full text-[10px] uppercase tracking-wider font-semibold print:hidden">
          {question.metadata.subtype.replace(/_/g, ' ')}
        </span>

        {/* Edit Button (Hidden if submitted or printing) */}
        {!isSubmitted && (
            <button 
                onClick={() => setIsEditing(true)}
                className="ml-auto text-blue-600 hover:text-blue-800 flex items-center gap-1 px-2 py-1 hover:bg-blue-50 rounded transition-colors print:hidden"
            >
                <Edit2 className="w-3 h-3" /> Edit
            </button>
        )}
      </div>

      <div className="p-6">
        {/* Vignette */}
        <p className="text-slate-800 leading-relaxed mb-4 text-base print:text-black">
          {question.vignette}
        </p>

        {/* Lead In */}
        <p className="font-medium text-slate-900 mb-6 italic print:text-black">
          {question.leadIn}
        </p>

        {/* Options */}
        <div className="space-y-3">
          {(['A', 'B', 'C', 'D'] as const).map((opt) => (
            <button
              key={opt}
              onClick={() => !isSubmitted && onSelectOption(opt)}
              disabled={isSubmitted}
              className={`w-full text-left p-4 rounded-lg border transition-all duration-200 flex items-start gap-3 print:border-gray-300 print:p-2 ${getOptionStyle(opt)}`}
            >
              <span className={`font-semibold min-w-[1.5rem] print:text-black ${isSubmitted && opt === question.correctAnswer ? 'text-green-700' : 'text-slate-500'}`}>
                {opt}
              </span>
              <span className="text-slate-800 print:text-black">{question.options[opt]}</span>
              {isSubmitted && opt === question.correctAnswer && (
                <CheckCircle2 className="w-5 h-5 text-green-600 ml-auto flex-shrink-0 print:hidden" />
              )}
              {isSubmitted && selectedOption === opt && opt !== question.correctAnswer && (
                <XCircle className="w-5 h-5 text-red-500 ml-auto flex-shrink-0 print:hidden" />
              )}
            </button>
          ))}
        </div>

        {/* Status / Explanation (Hidden in Print Mode usually, separate key used instead) */}
        {isSubmitted && (
            <div className="mt-6 print:hidden">
                <div 
                    className={`flex items-center gap-2 mb-2 font-semibold ${selectedOption === question.correctAnswer ? 'text-green-600' : 'text-red-500'}`}
                >
                    {selectedOption === question.correctAnswer ? 'Correct' : 'Incorrect'}
                </div>

                <div className="p-4 bg-slate-50 rounded-lg border border-slate-200 animate-fadeIn">
                    <h4 className="text-sm font-bold text-slate-900 mb-2">Explanation</h4>
                    <p className="text-sm text-slate-700 leading-relaxed">
                    {question.explanation}
                    </p>
                    <div className="mt-3 pt-3 border-t border-slate-200 text-xs text-slate-500">
                        LOs Tested: {question.metadata.losTested.join(', ')}
                    </div>
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

export default QuestionCard;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { UploadedFile, ExamQuestion, ExamAttempt, Project, DifficultyLevel, BlueprintSection } from './types';
import FileUpload from './components/FileUpload';
import QuestionCard from './components/QuestionCard';
import AnalyticsDashboard from './components/AnalyticsDashboard';
import ProjectList from './components/ProjectList';
import { generateExam } from './services/geminiService';
import { saveProject, getAllProjects, deleteProject } from './services/storageService';
import { Stethoscope, Loader2, Key, ChevronDown, ChevronUp, Download, ArrowRight, AlertTriangle, History, CheckCheck, BarChart2, Layout, ArrowLeft, SignalHigh, SignalMedium, SignalLow, Layers, Hash, Printer, Lock, MessageSquare, Send } from 'lucide-react';
import { useReactToPrint } from 'react-to-print';

// --- CONFIGURATION ---
const BETA_PASSWORD = "medbeta"; // Change this to your desired password
const FEEDBACK_EMAIL = "your-email@example.com"; // Change this to your email

function App() {
  // --- Auth State ---
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [passwordInput, setPasswordInput] = useState('');
  const [authError, setAuthError] = useState(false);
  const [showFeedback, setShowFeedback] = useState(false);
  const [feedbackText, setFeedbackText] = useState('');

  // --- Global State ---
  const [projects, setProjects] = useState<Project[]>([]);
  const [activeProject, setActiveProject] = useState<Project | null>(null);
  const [loadingProjects, setLoadingProjects] = useState(true);

  // --- UI State (Local to session) ---
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<'exam' | 'analytics'>('exam');

  // --- Initialization ---
  useEffect(() => {
    // Check session storage to keep user logged in on refresh
    const sessionAuth = sessionStorage.getItem('medexam_auth');
    if (sessionAuth === 'true') {
        setIsAuthenticated(true);
        loadProjects();
    } else {
        setLoadingProjects(false);
    }
  }, []);

  const handleLogin = (e: React.FormEvent) => {
      e.preventDefault();
      if (passwordInput === BETA_PASSWORD) {
          setIsAuthenticated(true);
          sessionStorage.setItem('medexam_auth', 'true');
          loadProjects();
      } else {
          setAuthError(true);
      }
  };

  const handleFeedbackSubmit = () => {
      const subject = encodeURIComponent("MedExam Beta Feedback");
      const body = encodeURIComponent(feedbackText);
      window.open(`mailto:${FEEDBACK_EMAIL}?subject=${subject}&body=${body}`);
      setShowFeedback(false);
      setFeedbackText('');
  };

  const loadProjects = async () => {
    setLoadingProjects(true);
    const loadedProjects = await getAllProjects();
    setProjects(loadedProjects);
    setLoadingProjects(false);
  };

  const handleCreateProject = async (name: string, description: string, blueprint: BlueprintSection[], referenceTotal: number) => {
    const newProject: Project = {
        id: crypto.randomUUID(),
        name,
        description,
        lastModified: new Date().toISOString(),
        referenceTotalQuestions: referenceTotal,
        learningObjectivesFiles: [],
        blueprint: blueprint,
        examHistory: [],
        activeExam: {
            questions: [],
            userAnswers: {},
            status: 'active',
            configOpen: true,
            questionCount: 10,
            difficulty: 'standard'
        }
    };
    await saveProject(newProject);
    setProjects(prev => [newProject, ...prev]);
    setActiveProject(newProject);
  };

  const handleDeleteProject = async (id: string) => {
    await deleteProject(id);
    setProjects(prev => prev.filter(p => p.id !== id));
    if (activeProject?.id === id) setActiveProject(null);
  };

  const updateActiveProject = useCallback(async (updatedProject: Project) => {
    setActiveProject(updatedProject);
    setProjects(prev => prev.map(p => p.id === updatedProject.id ? updatedProject : p));
    await saveProject(updatedProject);
  }, []);

  // --- Project Specific Handlers ---

  const handleLoFilesChange = (files: UploadedFile[]) => {
    if (!activeProject) return;
    updateActiveProject({ ...activeProject, learningObjectivesFiles: files });
  };

  // Handle uploading files to a specific bucket/section
  const handleSectionFilesChange = (sectionId: string, files: UploadedFile[]) => {
    if (!activeProject) return;
    const updatedBlueprint = activeProject.blueprint.map(section => 
        section.id === sectionId ? { ...section, files } : section
    );
    updateActiveProject({ ...activeProject, blueprint: updatedBlueprint });
  };

  const handleQuestionCountChange = (count: number) => {
      if (!activeProject) return;
      updateActiveProject({
          ...activeProject,
          activeExam: { ...activeProject.activeExam, questionCount: count }
      });
  };

  const handleDifficultyChange = (level: DifficultyLevel) => {
    if (!activeProject) return;
    updateActiveProject({
        ...activeProject,
        activeExam: { ...activeProject.activeExam, difficulty: level }
    });
  };

  const handleConfigToggle = () => {
      if (!activeProject) return;
      updateActiveProject({
          ...activeProject,
          activeExam: { ...activeProject.activeExam, configOpen: !activeProject.activeExam.configOpen }
      });
  };

  const handleGenerate = async () => {
    if (!activeProject) return;

    // Validate that at least some content exists
    const hasLOs = activeProject.learningObjectivesFiles.length > 0;
    const hasContent = activeProject.blueprint.some(s => s.files.length > 0);

    if (!hasLOs && !hasContent) {
      setError("Please upload at least one file (Learning Objectives or Content in a Section).");
      return;
    }

    setLoading(true);
    setError(null);

    const resetExamState = {
        ...activeProject.activeExam,
        questions: [],
        userAnswers: {},
        status: 'active' as const,
        configOpen: false
    };
    setActiveProject({ ...activeProject, activeExam: resetExamState });

    try {
      const generatedQuestions = await generateExam(
          activeProject.learningObjectivesFiles, 
          activeProject.blueprint, 
          activeProject.activeExam.questionCount,
          activeProject.activeExam.difficulty || 'standard',
          activeProject.referenceTotalQuestions || 40 // Pass the reference total
      );

      const newExamState = {
          ...resetExamState,
          questions: generatedQuestions
      };

      updateActiveProject({ ...activeProject, activeExam: newExamState });
      setActiveTab('exam');
    } catch (err: any) {
      setError(err.message || "Failed to generate exam. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const handleOptionSelect = (questionId: number, option: string) => {
    if (!activeProject) return;
    const updatedAnswers = {
        ...activeProject.activeExam.userAnswers,
        [questionId]: option
    };
    updateActiveProject({
        ...activeProject,
        activeExam: { ...activeProject.activeExam, userAnswers: updatedAnswers }
    });
  };

  const handleUpdateQuestion = (updatedQuestion: ExamQuestion) => {
    if (!activeProject) return;
    const updatedQuestions = activeProject.activeExam.questions.map(q => 
        q.id === updatedQuestion.id ? updatedQuestion : q
    );
    updateActiveProject({
        ...activeProject,
        activeExam: { ...activeProject.activeExam, questions: updatedQuestions }
    });
  };

  const calculateScore = () => {
    if (!activeProject) return 0;
    let score = 0;
    activeProject.activeExam.questions.forEach(q => {
        if (activeProject.activeExam.userAnswers[q.id] === q.correctAnswer) {
            score++;
        }
    });
    return score;
  };

  const handleFinishExam = () => {
    if (!activeProject || activeProject.activeExam.questions.length === 0) return;
    const { questions, userAnswers } = activeProject.activeExam;

    if (Object.keys(userAnswers).length < questions.length) {
        if (!window.confirm(`You have answered ${Object.keys(userAnswers).length} out of ${questions.length} questions. Are you sure you want to submit?`)) {
            return;
        }
    }

    const finalScore = calculateScore();
    const attempt: ExamAttempt = {
        id: crypto.randomUUID(),
        date: new Date().toISOString(),
        score: finalScore,
        totalQuestions: questions.length,
        answers: { ...userAnswers },
        questions: [ ...questions ]
    };

    updateActiveProject({
        ...activeProject,
        examHistory: [...activeProject.examHistory, attempt],
        activeExam: { ...activeProject.activeExam, status: 'completed' }
    });

    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handlePrint = () => {
    window.print();
  };

  const handleDownload = () => {
    if (!activeProject) return;
    const { questions, userAnswers } = activeProject.activeExam;
    const content = questions.map((q, i) => `
Q${i+1}. ${q.vignette}
${q.leadIn}
A. ${q.options.A}
B. ${q.options.B}
C. ${q.options.C}
D. ${q.options.D}

User Answer: ${userAnswers[q.id] || "Skipped"}
Correct: ${q.correctAnswer}
Explanation: ${q.explanation}
Metadata: [${q.metadata.cognitiveLevel}, ${q.metadata.cluster}]
`).join('\n---\n');

    const blob = new Blob([content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${activeProject.name.replace(/\s+/g, '_')}_Exam_${new Date().toISOString().slice(0,10)}.txt`;
    a.click();
    URL.revokeObjectURL(url);
  };

  // --- BETA AUTH VIEW ---
  if (!isAuthenticated) {
      return (
        <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
            <div className="bg-white max-w-md w-full p-8 rounded-2xl shadow-xl border border-slate-100">
                <div className="flex justify-center mb-6">
                    <div className="bg-blue-600 p-3 rounded-xl shadow-lg shadow-blue-200">
                        <Stethoscope className="w-8 h-8 text-white" />
                    </div>
                </div>
                <h1 className="text-2xl font-bold text-center text-slate-900 mb-2">MedExam Generator</h1>
                <div className="flex justify-center mb-8">
                     <span className="bg-blue-100 text-blue-700 text-xs font-bold px-3 py-1 rounded-full uppercase tracking-wider">Beta Access</span>
                </div>

                <form onSubmit={handleLogin} className="space-y-4">
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">Access Password</label>
                        <div className="relative">
                            <input 
                                type="password" 
                                value={passwordInput}
                                onChange={(e) => {
                                    setPasswordInput(e.target.value);
                                    setAuthError(false);
                                }}
                                className={`w-full px-4 py-3 border rounded-xl outline-none focus:ring-2 transition-all ${authError ? 'border-red-300 focus:ring-red-200' : 'border-slate-200 focus:ring-blue-500 focus:border-blue-500'}`}
                                placeholder="Enter beta password"
                            />
                            <Lock className="w-5 h-5 text-slate-400 absolute right-3 top-3.5" />
                        </div>
                        {authError && <p className="text-red-500 text-sm mt-1 ml-1">Incorrect password</p>}
                    </div>
                    <button 
                        type="submit"
                        className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 rounded-xl transition-all shadow-md hover:shadow-lg transform active:scale-95"
                    >
                        Enter App
                    </button>
                </form>
                <p className="text-center text-slate-400 text-xs mt-6">
                    Restricted usage for testing purposes only.
                </p>
            </div>
        </div>
      );
  }

  if (loadingProjects) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50">
        <Loader2 className="w-8 h-8 text-blue-600 animate-spin" />
      </div>
    );
  }

  // --- FEEDBACK MODAL ---
  const FeedbackModal = () => (
      <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4 animate-fadeIn">
          <div className="bg-white rounded-xl shadow-2xl max-w-md w-full p-6 relative">
              <button 
                onClick={() => setShowFeedback(false)}
                className="absolute top-4 right-4 text-slate-400 hover:text-slate-600"
              >
                  <X className="w-5 h-5" />
              </button>
              <h3 className="text-xl font-bold text-slate-900 mb-4 flex items-center gap-2">
                  <MessageSquare className="w-5 h-5 text-blue-600" /> Beta Feedback
              </h3>
              <p className="text-sm text-slate-500 mb-4">
                  Found a bug or have an idea? Let us know! This will open your default email client.
              </p>
              <textarea 
                  value={feedbackText}
                  onChange={(e) => setFeedbackText(e.target.value)}
                  placeholder="Describe your issue or suggestion..."
                  className="w-full h-32 p-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none resize-none mb-4 text-sm"
              />
              <button 
                  onClick={handleFeedbackSubmit}
                  disabled={!feedbackText.trim()}
                  className="w-full bg-blue-600 hover:bg-blue-700 disabled:bg-slate-300 disabled:cursor-not-allowed text-white font-bold py-2 rounded-lg flex items-center justify-center gap-2"
              >
                  <Send className="w-4 h-4" /> Send Feedback
              </button>
          </div>
      </div>
  );

  // --- VIEW: PROJECT LIST ---
  if (!activeProject) {
      return (
          <div className="min-h-screen bg-slate-50">
             <header className="bg-white border-b border-slate-200 shadow-sm">
                <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
                    <div className="flex items-center space-x-3">
                        <div className="bg-blue-600 p-2 rounded-lg">
                            <Stethoscope className="w-5 h-5 text-white" />
                        </div>
                        <h1 className="text-xl font-bold text-slate-900 tracking-tight">MedExam Generator</h1>
                        <span className="bg-blue-100 text-blue-800 text-[10px] font-bold px-2 py-0.5 rounded uppercase">Beta</span>
                    </div>
                </div>
            </header>
            <ProjectList 
                projects={projects} 
                onSelectProject={setActiveProject}
                onCreateProject={handleCreateProject}
                onDeleteProject={handleDeleteProject}
            />

            {/* Feedback Button */}
            <button 
                onClick={() => setShowFeedback(true)}
                className="fixed bottom-6 right-6 bg-slate-900 hover:bg-slate-800 text-white p-4 rounded-full shadow-lg hover:shadow-xl transition-all z-40 flex items-center gap-2 group"
            >
                <MessageSquare className="w-6 h-6" />
                <span className="max-w-0 overflow-hidden group-hover:max-w-xs transition-all duration-300 whitespace-nowrap font-medium text-sm">Feedback</span>
            </button>
            {showFeedback && <FeedbackModal />}
          </div>
      );
  }

  // --- VIEW: PROJECT WORKSPACE ---
  const { activeExam, learningObjectivesFiles, blueprint, examHistory } = activeProject;
  const currentDifficulty = activeExam.difficulty || 'standard';

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col print:bg-white">
      {/* Header - Hidden in Print */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-20 shadow-sm print:hidden">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-4">
             <button 
                onClick={() => setActiveProject(null)}
                className="p-2 -ml-2 text-slate-500 hover:text-blue-600 hover:bg-slate-100 rounded-lg transition-colors"
                title="Back to Projects"
             >
                 <ArrowLeft className="w-5 h-5" />
             </button>
             <div className="h-6 w-px bg-slate-200 mx-1"></div>
             <div>
                <h1 className="text-lg font-bold text-slate-900 tracking-tight leading-tight">{activeProject.name}</h1>
                <p className="text-xs text-slate-500 hidden sm:block">Project Workspace</p>
             </div>
          </div>

          <div className="flex items-center gap-2">
            <nav className="flex items-center p-1 bg-slate-100 rounded-lg mr-2">
                <button 
                    onClick={() => setActiveTab('exam')}
                    className={`flex items-center gap-2 px-3 py-1.5 text-sm font-medium rounded-md transition-all ${activeTab === 'exam' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                >
                    <Layout className="w-4 h-4" /> <span className="hidden sm:inline">Exam</span>
                </button>
                <button 
                    onClick={() => setActiveTab('analytics')}
                    className={`flex items-center gap-2 px-3 py-1.5 text-sm font-medium rounded-md transition-all ${activeTab === 'analytics' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                >
                    <BarChart2 className="w-4 h-4" /> <span className="hidden sm:inline">Progress</span>
                </button>
            </nav>
          </div>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 py-8 w-full flex-grow print:max-w-none print:p-0">

        {activeTab === 'exam' && (
            <div className="flex items-center gap-2 mb-4 text-xs text-slate-500 justify-end print:hidden">
                <History className="w-3 h-3" />
                <span>Auto-saved</span>
            </div>
        )}

        {/* ANALYTICS TAB */}
        {activeTab === 'analytics' && (
            <div className="animate-fadeIn print:hidden">
                <h2 className="text-2xl font-bold text-slate-900 mb-6">Performance Analytics: {activeProject.name}</h2>
                <AnalyticsDashboard history={examHistory} />
            </div>
        )}

        {/* EXAM TAB */}
        {activeTab === 'exam' && (
        <>
            {/* Configuration Panel - Hidden in Print */}
            <div className={`bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden mb-8 transition-all duration-300 print:hidden ${!activeExam.configOpen && activeExam.questions.length > 0 ? 'opacity-80 hover:opacity-100' : ''}`}>
            <div 
                className="px-6 py-4 bg-slate-50 border-b border-slate-200 flex items-center justify-between cursor-pointer"
                onClick={handleConfigToggle}
            >
                <h2 className="font-semibold text-slate-900 flex items-center gap-2">
                    <Key className="w-4 h-4 text-slate-500" />
                    Generator Configuration
                </h2>
                {activeExam.configOpen ? <ChevronUp className="w-4 h-4 text-slate-500"/> : <ChevronDown className="w-4 h-4 text-slate-500"/>}
            </div>

            {activeExam.configOpen && (
                <div className="p-6 space-y-8 animate-fadeIn">

                    {/* GLOBAL LEARNING OBJECTIVES */}
                    <div className="bg-slate-50 p-4 rounded-lg border border-slate-200">
                         <div className="flex items-center gap-2 mb-4">
                            <span className="flex items-center justify-center w-6 h-6 rounded-full bg-blue-100 text-blue-700 text-xs font-bold">1</span>
                            <h3 className="font-semibold text-slate-900">Learning Objectives (Global)</h3>
                        </div>
                        <FileUpload 
                            id="lo-upload"
                            files={learningObjectivesFiles} 
                            onFilesChanged={handleLoFilesChange} 
                            title="Weekly LOs (XLSX, PDF, Doc)"
                            description="Upload the master list of Learning Objectives"
                            className="bg-white"
                        />
                    </div>

                    {/* BLUEPRINT SECTIONS */}
                    <div>
                        <div className="flex items-center gap-2 mb-4">
                            <span className="flex items-center justify-center w-6 h-6 rounded-full bg-blue-100 text-blue-700 text-xs font-bold">2</span>
                            <h3 className="font-semibold text-slate-900">Content Breakdown</h3>
                        </div>

                        <div className="grid grid-cols-1 gap-6">
                            {blueprint.map((section) => (
                                <div key={section.id} className="border border-slate-200 rounded-lg p-4 relative">
                                    <div className="absolute top-0 right-0 bg-slate-100 px-3 py-1 text-xs font-bold text-slate-600 rounded-bl-lg border-l border-b border-slate-200 flex items-center gap-1">
                                        <Hash className="w-3 h-3 text-slate-400" />
                                        {section.questionCount} Questions (Ref)
                                    </div>
                                    <h4 className="font-bold text-slate-800 mb-1 flex items-center gap-2">
                                        <Layers className="w-4 h-4 text-slate-400" /> {section.title}
                                    </h4>
                                    <p className="text-xs text-slate-500 mb-4">{section.description}</p>

                                    <FileUpload 
                                        id={`section-${section.id}`}
                                        files={section.files} 
                                        onFilesChanged={(files) => handleSectionFilesChange(section.id, files)}
                                        title={`Upload Material for ${section.title}`}
                                        description="Lecture slides, notes, or transcripts specific to this section"
                                    />
                                </div>
                            ))}
                        </div>
                    </div>

                    <hr className="border-slate-100" />

                    {/* Settings Grid */}
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        {/* Difficulty Selector */}
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-2">
                                Difficulty Level
                            </label>
                            <div className="grid grid-cols-3 gap-2 bg-slate-50 p-1.5 rounded-lg border border-slate-200">
                                <button
                                    onClick={() => handleDifficultyChange('standard')}
                                    className={`flex items-center justify-center gap-1.5 py-2 px-3 rounded-md text-sm font-medium transition-all ${currentDifficulty === 'standard' ? 'bg-white text-blue-600 shadow-sm border border-slate-100' : 'text-slate-500 hover:text-slate-700 hover:bg-slate-200/50'}`}
                                >
                                    <SignalLow className="w-4 h-4" /> Standard
                                </button>
                                <button
                                    onClick={() => handleDifficultyChange('hard')}
                                    className={`flex items-center justify-center gap-1.5 py-2 px-3 rounded-md text-sm font-medium transition-all ${currentDifficulty === 'hard' ? 'bg-white text-yellow-600 shadow-sm border border-slate-100' : 'text-slate-500 hover:text-slate-700 hover:bg-slate-200/50'}`}
                                >
                                    <SignalMedium className="w-4 h-4" /> Hard
                                </button>
                                <button
                                    onClick={() => handleDifficultyChange('expert')}
                                    className={`flex items-center justify-center gap-1.5 py-2 px-3 rounded-md text-sm font-medium transition-all ${currentDifficulty === 'expert' ? 'bg-white text-red-600 shadow-sm border border-slate-100' : 'text-slate-500 hover:text-slate-700 hover:bg-slate-200/50'}`}
                                >
                                    <SignalHigh className="w-4 h-4" /> Expert
                                </button>
                            </div>
                        </div>

                        {/* Question Count */}
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-2">
                                Generate Questions (Mock Exam Size)
                            </label>
                            <div className="flex items-center gap-4 bg-slate-50 p-3 rounded-lg border border-slate-200 h-[50px]">
                                <input 
                                    type="range" 
                                    min="5" 
                                    max="50" 
                                    step="1"
                                    value={activeExam.questionCount}
                                    onChange={(e) => handleQuestionCountChange(parseInt(e.target.value))}
                                    className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-blue-600"
                                />
                                <span className="font-mono text-lg font-bold w-12 text-center text-blue-600 bg-white rounded border border-slate-200 px-2 py-0.5 text-sm">
                                    {activeExam.questionCount}
                                </span>
                            </div>
                        </div>
                    </div>

                    {/* Generate Button */}
                    <button
                        onClick={handleGenerate}
                        disabled={loading}
                        className={`w-full py-4 px-6 rounded-xl font-bold text-lg shadow-sm transition-all flex items-center justify-center space-x-2
                        ${loading
                            ? 'bg-slate-100 text-slate-400 cursor-not-allowed border border-slate-200' 
                            : 'bg-blue-600 text-white hover:bg-blue-700 hover:shadow-lg hover:-translate-y-0.5'
                        }`}
                    >
                        {loading ? (
                        <>
                            <Loader2 className="w-6 h-6 animate-spin" />
                            <span>Analyzing & Generating...</span>
                        </>
                        ) : (
                        <>
                            <span>Generate Practice Exam</span>
                            <ArrowRight className="w-5 h-5" />
                        </>
                        )}
                    </button>

                    {error && (
                        <div className="p-4 bg-red-50 text-red-700 text-sm rounded-lg border border-red-200 flex items-start gap-2">
                            <AlertTriangle className="w-5 h-5 flex-shrink-0 mt-0.5" />
                            <div>
                                <div className="font-bold">Generation Failed</div>
                                <div>{error}</div>
                            </div>
                        </div>
                    )}
                </div>
            )}
            </div>

            {/* Results Header with Score */}
            {activeExam.questions.length > 0 && (
            <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4 mb-6 print:mb-8">
                 <div className="print:hidden">
                    <h3 className="text-2xl font-bold text-slate-900 flex items-center gap-2">
                        {activeExam.status === 'completed' ? 'Exam Results' : 'Active Exam'}
                        {activeExam.difficulty === 'expert' && <span className="bg-red-100 text-red-700 text-xs px-2 py-0.5 rounded-full font-bold uppercase">Expert</span>}
                        {activeExam.difficulty === 'hard' && <span className="bg-yellow-100 text-yellow-700 text-xs px-2 py-0.5 rounded-full font-bold uppercase">Hard</span>}
                    </h3>
                    <p className="text-slate-500 mt-1">
                        {activeExam.status === 'completed' 
                            ? `You scored ${calculateScore()} out of ${activeExam.questions.length} (${Math.round((calculateScore()/activeExam.questions.length)*100)}%)` 
                            : `${Object.keys(activeExam.userAnswers).length} of ${activeExam.questions.length} questions answered`}
                    </p>
                 </div>

                 {/* Print Header */}
                 <div className="hidden print:block w-full text-center mb-8 border-b-2 border-black pb-4">
                     <h1 className="text-3xl font-bold text-black">{activeProject.name} - Practice Exam</h1>
                     <p className="text-gray-600 mt-2">Questions: {activeExam.questions.length} | Difficulty: {activeExam.difficulty?.toUpperCase() || 'STANDARD'}</p>
                 </div>

                 <div className="flex items-center gap-3 print:hidden">
                    <button
                        onClick={handlePrint}
                        className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-slate-700 bg-white border border-slate-200 hover:bg-slate-50 rounded-lg transition-colors shadow-sm"
                    >
                        <Printer className="w-4 h-4" /> Print
                    </button>
                    {activeExam.status === 'completed' && (
                        <button
                        onClick={handleDownload}
                        className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-slate-700 bg-white border border-slate-200 hover:bg-slate-50 rounded-lg transition-colors shadow-sm"
                        >
                            <Download className="w-4 h-4" /> Export
                        </button>
                     )}

                     {activeExam.status === 'active' && (
                         <button
                         onClick={handleFinishExam}
                         className="flex items-center gap-2 px-6 py-2 text-sm font-bold text-white bg-green-600 hover:bg-green-700 rounded-lg transition-colors shadow-sm hover:shadow"
                         >
                             <CheckCheck className="w-4 h-4" /> Finish Exam
                         </button>
                     )}
                 </div>
            </div>
            )}

            {/* Question List */}
            {activeExam.questions.length > 0 && (
            <div className="space-y-6 animate-slideUp print:space-y-8">
                {activeExam.questions.map((q, index) => (
                <QuestionCard 
                    key={q.id || index} 
                    question={q} 
                    index={index} 
                    selectedOption={activeExam.userAnswers[q.id] || null}
                    onSelectOption={(opt) => handleOptionSelect(q.id, opt)}
                    onUpdateQuestion={handleUpdateQuestion}
                    isSubmitted={activeExam.status === 'completed'}
                />
                ))}

                {/* Answer Key for Print */}
                <div className="hidden print:block break-before-page">
                    <h2 className="text-2xl font-bold mb-6 border-b-2 border-black pb-2">Answer Key & Explanations</h2>
                    <div className="space-y-6">
                        {activeExam.questions.map((q, i) => (
                            <div key={i} className="mb-4">
                                <div className="font-bold text-lg mb-1">Question {i+1}: <span className="text-black">{q.correctAnswer}</span></div>
                                <p className="text-sm text-gray-700">{q.explanation}</p>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Bottom Finish Button (if long exam) */}
                {activeExam.questions.length > 3 && activeExam.status === 'active' && (
                    <div className="flex justify-center pt-8 pb-12 print:hidden">
                         <button
                         onClick={handleFinishExam}
                         className="flex items-center gap-2 px-8 py-4 text-lg font-bold text-white bg-green-600 hover:bg-green-700 rounded-xl transition-all shadow-md hover:shadow-lg hover:-translate-y-0.5"
                         >
                             <CheckCheck className="w-5 h-5" /> Finish & Submit Exam
                         </button>
                    </div>
                )}
            </div>
            )}

            {/* Empty State */}
            {!loading && activeExam.questions.length === 0 && !activeExam.configOpen && (
                <div className="text-center py-12 bg-slate-50 rounded-xl border border-dashed border-slate-300 print:hidden">
                    <p className="text-slate-500 font-medium">Exam generation complete or pending. <button onClick={handleConfigToggle} className="text-blue-600 hover:underline">Open configuration</button> to start.</p>
                </div>
            )}
        </>
        )}
      </main>

      {/* Floating Feedback Button (Project View) */}
      <button 
        onClick={() => setShowFeedback(true)}
        className="fixed bottom-6 right-6 bg-slate-900 hover:bg-slate-800 text-white p-4 rounded-full shadow-lg hover:shadow-xl transition-all z-40 flex items-center gap-2 group print:hidden"
      >
        <MessageSquare className="w-6 h-6" />
        <span className="max-w-0 overflow-hidden group-hover:max-w-xs transition-all duration-300 whitespace-nowrap font-medium text-sm">Feedback</span>
      </button>
      {showFeedback && <FeedbackModal />}
    </div>
  );
}

export default App;

import React, { useMemo, useState } from 'react';
import { ExamAttempt } from '../types';
import { 
  BarChart3, 
  TrendingUp, 
  Calendar, 
  Target, 
  CheckCircle2, 
  AlertTriangle, 
  BookOpen, 
  BrainCircuit, 
  List,
  ArrowUpRight,
  Download
} from 'lucide-react';

interface AnalyticsDashboardProps {
  history: ExamAttempt[];
}

interface PerformanceMetric {
  correct: number;
  total: number;
  percentage: number;
}

interface StudyInsight {
  topic: string;
  score: number;
  type: 'strength' | 'weakness' | 'neutral';
}

const AnalyticsDashboard: React.FC<AnalyticsDashboardProps> = ({ history }) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'objectives'>('overview');

  const stats = useMemo(() => {
    if (history.length === 0) return null;

    let totalScore = 0;
    let totalQuestions = 0;

    // Detailed Aggregations
    const weekStats: Record<string, { correct: number, total: number }> = {};
    const levelStats: Record<string, { correct: number, total: number }> = {};
    const clusterStats: Record<string, { correct: number, total: number }> = {};
    const loStats: Record<string, { correct: number, total: number }> = {};

    history.forEach(attempt => {
      totalScore += attempt.score;
      totalQuestions += attempt.totalQuestions;

      attempt.questions.forEach((q) => {
        const isCorrect = attempt.answers[q.id] === q.correctAnswer;

        // Helper to update stats
        const updateStat = (record: Record<string, { correct: number, total: number }>, key: string) => {
          if (!record[key]) record[key] = { correct: 0, total: 0 };
          record[key].total++;
          if (isCorrect) record[key].correct++;
        };

        // Update High Level Categories
        updateStat(weekStats, `Week ${q.metadata.week}`);
        updateStat(levelStats, `Level ${q.metadata.cognitiveLevel}`);

        // Clean cluster name (remove slashes for cleaner display if needed, or keep as is)
        const clusterName = q.metadata.cluster.trim(); 
        updateStat(clusterStats, clusterName);

        // Update Specific LOs
        q.metadata.losTested.forEach(lo => {
          updateStat(loStats, lo.trim());
        });
      });
    });

    // Helper to format into arrays for rendering
    const formatStats = (record: Record<string, { correct: number, total: number }>): [string, PerformanceMetric][] => {
      return Object.entries(record).map(([key, val]) => [
        key, 
        { ...val, percentage: Math.round((val.correct / val.total) * 100) }
      ]);
    };

    const weekPerformance = formatStats(weekStats).sort((a, b) => a[0].localeCompare(b[0]));
    const levelPerformance = formatStats(levelStats).sort((a, b) => a[0].localeCompare(b[0]));

    // Sort clusters by performance (worst to best for analysis)
    const clusterPerformance = formatStats(clusterStats).sort((a, b) => a[1].percentage - b[1].percentage);

    // Sort LOs by performance (worst to best), then by number of questions (relevance)
    const loPerformance = formatStats(loStats).sort((a, b) => {
      if (a[1].percentage !== b[1].percentage) return a[1].percentage - b[1].percentage;
      return b[1].total - a[1].total; 
    });

    const averageAccuracy = Math.round((totalScore / totalQuestions) * 100);

    return {
      totalAttempts: history.length,
      averageAccuracy,
      totalQuestionsAnswered: totalQuestions,
      weekPerformance,
      levelPerformance,
      clusterPerformance,
      loPerformance
    };
  }, [history]);

  // --- Insight Generation Logic ---
  const insights = useMemo(() => {
    if (!stats) return { strengths: [], weaknesses: [], recommendations: [] };

    // Identify Weaknesses (< 60%)
    const weaknesses = stats.clusterPerformance
      .filter(([_, metric]) => metric.percentage < 60)
      .slice(0, 3)
      .map(([topic, metric]) => ({ topic, score: metric.percentage, type: 'weakness' as const }));

    // Identify Strengths (> 80%)
    const strengths = stats.clusterPerformance
      .filter(([_, metric]) => metric.percentage >= 80)
      .sort((a, b) => b[1].percentage - a[1].percentage)
      .slice(0, 3)
      .map(([topic, metric]) => ({ topic, score: metric.percentage, type: 'strength' as const }));

    // Generate Recommendations
    const recommendations: string[] = [];

    if (weaknesses.length > 0) {
      recommendations.push(`Prioritize reviewing lecture slides related to **${weaknesses.map(w => w.topic).join(', ')}**.`);
    }

    // Check Cognitive Levels
    const logicMetric = stats.levelPerformance.find(l => l[0] === 'Level 1.3')?.[1];
    const recallMetric = stats.levelPerformance.find(l => l[0] === 'Level 1.1')?.[1];

    if (logicMetric && logicMetric.percentage < 50) {
      recommendations.push("Your clinical reasoning (Level 1.3) scores are lower. Focus on practice cases that require connecting multiple findings rather than just memorizing facts.");
    }
    if (recallMetric && recallMetric.percentage < 50) {
      recommendations.push("Your factual recall (Level 1.1) is low. Consider using flashcards to solidify core definitions and anatomy.");
    }

    if (recommendations.length === 0) {
      recommendations.push("You are maintaining a balanced performance. Continue your current study routine and try generating harder question sets.");
    }

    return { strengths, weaknesses, recommendations };
  }, [stats]);

  const handleExportData = () => {
      const dataStr = JSON.stringify(history, null, 2);
      const blob = new Blob([dataStr], { type: "application/json" });
      const url = URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.href = url;
      a.download = `medexam_research_data_${new Date().toISOString().slice(0,10)}.json`;
      a.click();
      URL.revokeObjectURL(url);
  };

  if (!stats) {
    return (
      <div className="text-center py-12 bg-white rounded-xl border border-slate-200">
        <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4">
          <BarChart3 className="w-8 h-8 text-slate-300" />
        </div>
        <h3 className="text-lg font-medium text-slate-900">No Data Yet</h3>
        <p className="text-slate-500 mt-1">Complete an exam to see your performance analytics.</p>
      </div>
    );
  }

  const renderProgressBar = (label: string, metric: PerformanceMetric) => {
    const colorClass = metric.percentage >= 80 ? 'bg-green-500' : metric.percentage >= 60 ? 'bg-yellow-500' : 'bg-red-500';
    return (
      <div key={label} className="mb-4 last:mb-0">
        <div className="flex justify-between text-sm mb-1.5">
          <span className="font-medium text-slate-700 truncate pr-2" title={label}>{label}</span>
          <span className="text-slate-500 flex-shrink-0">{metric.correct}/{metric.total} ({metric.percentage}%)</span>
        </div>
        <div className="w-full bg-slate-100 rounded-full h-2.5 overflow-hidden">
          <div className={`h-2.5 rounded-full transition-all duration-500 ${colorClass}`} style={{ width: `${metric.percentage}%` }}></div>
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-8 animate-fadeIn">

      {/* 1. Header Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm flex items-center gap-4">
          <div className="p-3 bg-blue-50 rounded-full">
            <Target className="w-6 h-6 text-blue-600" />
          </div>
          <div>
            <div className="text-sm text-slate-500 font-medium">Avg Accuracy</div>
            <div className="text-3xl font-bold text-slate-900">{stats.averageAccuracy}%</div>
          </div>
        </div>
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm flex items-center gap-4">
          <div className="p-3 bg-purple-50 rounded-full">
            <TrendingUp className="w-6 h-6 text-purple-600" />
          </div>
          <div>
            <div className="text-sm text-slate-500 font-medium">Exams Taken</div>
            <div className="text-3xl font-bold text-slate-900">{stats.totalAttempts}</div>
          </div>
        </div>
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm flex items-center gap-4">
          <div className="p-3 bg-indigo-50 rounded-full">
            <BookOpen className="w-6 h-6 text-indigo-600" />
          </div>
          <div>
            <div className="text-sm text-slate-500 font-medium">Questions Answered</div>
            <div className="text-3xl font-bold text-slate-900">{stats.totalQuestionsAnswered}</div>
          </div>
        </div>
      </div>

      {/* 2. AI Study Coach Section */}
      <div className="bg-gradient-to-br from-white to-blue-50 rounded-xl border border-blue-100 shadow-sm p-6 relative overflow-hidden">
        <div className="absolute top-0 right-0 p-4 opacity-5">
            <BrainCircuit className="w-32 h-32" />
        </div>
        <h3 className="text-lg font-bold text-slate-900 mb-6 flex items-center gap-2">
            <BrainCircuit className="w-5 h-5 text-blue-600" />
            AI Study Coach
        </h3>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8 relative z-10">
            {/* Action Plan */}
            <div>
                <h4 className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-3">Recommended Focus</h4>
                <div className="space-y-4">
                    {insights.recommendations.map((rec, i) => (
                        <div key={i} className="flex items-start gap-3 bg-white/80 p-3 rounded-lg border border-blue-100">
                            <ArrowUpRight className="w-5 h-5 text-blue-600 flex-shrink-0 mt-0.5" />
                            <p className="text-sm text-slate-700 leading-relaxed" dangerouslySetInnerHTML={{ 
                                // Safe to use because we generate the text ourselves above
                                __html: rec.replace(/\*\*(.*?)\*\*/g, '<span class="font-bold text-slate-900">$1</span>') 
                            }} />
                        </div>
                    ))}
                </div>
            </div>

            {/* Strengths & Weaknesses */}
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div className="bg-white/60 rounded-lg p-4 border border-red-100">
                    <h4 className="text-xs font-bold text-red-600 uppercase tracking-wider mb-3 flex items-center gap-2">
                        <AlertTriangle className="w-4 h-4" /> Needs Attention
                    </h4>
                    {insights.weaknesses.length > 0 ? (
                        <ul className="space-y-2">
                            {insights.weaknesses.map(w => (
                                <li key={w.topic} className="flex justify-between items-center text-sm">
                                    <span className="text-slate-700 truncate mr-2" title={w.topic}>{w.topic}</span>
                                    <span className="font-bold text-red-600 bg-red-50 px-2 py-0.5 rounded text-xs">{w.score}%</span>
                                </li>
                            ))}
                        </ul>
                    ) : (
                        <p className="text-sm text-slate-500 italic">No major weaknesses detected yet.</p>
                    )}
                </div>

                <div className="bg-white/60 rounded-lg p-4 border border-green-100">
                    <h4 className="text-xs font-bold text-green-600 uppercase tracking-wider mb-3 flex items-center gap-2">
                        <CheckCircle2 className="w-4 h-4" /> Strong Topics
                    </h4>
                    {insights.strengths.length > 0 ? (
                        <ul className="space-y-2">
                            {insights.strengths.map(s => (
                                <li key={s.topic} className="flex justify-between items-center text-sm">
                                    <span className="text-slate-700 truncate mr-2" title={s.topic}>{s.topic}</span>
                                    <span className="font-bold text-green-600 bg-green-50 px-2 py-0.5 rounded text-xs">{s.score}%</span>
                                </li>
                            ))}
                        </ul>
                    ) : (
                         <p className="text-sm text-slate-500 italic">Keep practicing to establish strengths.</p>
                    )}
                </div>
            </div>
        </div>
      </div>

      {/* 3. Export Data Button (For Observation) */}
      <div className="flex justify-end">
          <button 
            onClick={handleExportData}
            className="flex items-center gap-2 px-4 py-2 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-lg text-sm font-medium transition-colors border border-slate-200"
            title="Download your exam history as a JSON file to share with researchers/developers"
          >
              <Download className="w-4 h-4" /> Export Research Data
          </button>
      </div>

      {/* 4. Detailed Metrics Tabs */}
      <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="flex border-b border-slate-200">
            <button 
                onClick={() => setActiveTab('overview')}
                className={`flex-1 py-4 text-sm font-medium text-center transition-colors border-b-2 ${activeTab === 'overview' ? 'border-blue-500 text-blue-600 bg-blue-50/50' : 'border-transparent text-slate-500 hover:text-slate-700 hover:bg-slate-50'}`}
            >
                Topic & Level Breakdown
            </button>
            <button 
                onClick={() => setActiveTab('objectives')}
                className={`flex-1 py-4 text-sm font-medium text-center transition-colors border-b-2 ${activeTab === 'objectives' ? 'border-blue-500 text-blue-600 bg-blue-50/50' : 'border-transparent text-slate-500 hover:text-slate-700 hover:bg-slate-50'}`}
            >
                Learning Objectives (LOs)
            </button>
        </div>

        <div className="p-6">
            {activeTab === 'overview' && (
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                     {/* Topic/Cluster Performance */}
                    <div>
                        <h3 className="text-base font-bold text-slate-900 mb-4 flex items-center gap-2">
                             <Target className="w-4 h-4 text-slate-500" /> Topic Performance
                        </h3>
                        <div className="space-y-1 max-h-80 overflow-y-auto pr-2 custom-scrollbar">
                            {stats.clusterPerformance.map(([topic, metric]) => renderProgressBar(topic, metric))}
                        </div>
                    </div>

                    <div className="space-y-8">
                        {/* Weekly Performance */}
                        <div>
                            <h3 className="text-base font-bold text-slate-900 mb-4 flex items-center gap-2">
                                <Calendar className="w-4 h-4 text-slate-500" /> Weekly Breakdown
                            </h3>
                            {stats.weekPerformance.map(([week, metric]) => renderProgressBar(week, metric))}
                        </div>

                         {/* Cognitive Level Performance */}
                         <div>
                            <h3 className="text-base font-bold text-slate-900 mb-4 flex items-center gap-2">
                                <BrainCircuit className="w-4 h-4 text-slate-500" /> Cognitive Levels
                            </h3>
                            {stats.levelPerformance.map(([level, metric]) => renderProgressBar(level, metric))}
                        </div>
                    </div>
                </div>
            )}

            {activeTab === 'objectives' && (
                <div>
                     <div className="flex items-center justify-between mb-4">
                        <h3 className="text-base font-bold text-slate-900 flex items-center gap-2">
                             <List className="w-4 h-4 text-slate-500" /> Learning Objective Breakdown
                        </h3>
                        <span className="text-xs text-slate-500">Sorted by lowest accuracy</span>
                     </div>

                     <div className="overflow-x-auto border border-slate-200 rounded-lg">
                         <table className="w-full text-sm text-left">
                             <thead className="bg-slate-50 text-slate-500 font-medium border-b border-slate-200">
                                 <tr>
                                     <th className="px-4 py-3">Learning Objective (LO)</th>
                                     <th className="px-4 py-3 w-32 text-center">Attempts</th>
                                     <th className="px-4 py-3 w-32 text-center">Score</th>
                                     <th className="px-4 py-3 w-24 text-center">Status</th>
                                 </tr>
                             </thead>
                             <tbody className="divide-y divide-slate-100">
                                 {stats.loPerformance.map(([lo, metric]) => (
                                     <tr key={lo} className="hover:bg-slate-50/50 transition-colors">
                                         <td className="px-4 py-3 text-slate-700 font-medium">
                                             {lo}
                                         </td>
                                         <td className="px-4 py-3 text-center text-slate-500">
                                             {metric.total}
                                         </td>
                                         <td className="px-4 py-3 text-center">
                                             <div className="flex items-center justify-center gap-2">
                                                 <span className={`font-bold ${metric.percentage >= 80 ? 'text-green-600' : metric.percentage >= 60 ? 'text-yellow-600' : 'text-red-600'}`}>
                                                     {metric.percentage}%
                                                 </span>
                                                 <span className="text-xs text-slate-400">
                                                     ({metric.correct}/{metric.total})
                                                 </span>
                                             </div>
                                         </td>
                                         <td className="px-4 py-3 text-center">
                                             {metric.percentage >= 80 ? (
                                                 <span className="inline-flex px-2 py-1 bg-green-100 text-green-700 rounded text-xs font-bold">Mastered</span>
                                             ) : metric.percentage < 60 ? (
                                                 <span className="inline-flex px-2 py-1 bg-red-100 text-red-700 rounded text-xs font-bold">Review</span>
                                             ) : (
                                                 <span className="inline-flex px-2 py-1 bg-yellow-100 text-yellow-700 rounded text-xs font-bold">Avg</span>
                                             )}
                                         </td>
                                     </tr>
                                 ))}
                             </tbody>
                         </table>
                         {stats.loPerformance.length === 0 && (
                            <div className="p-8 text-center text-slate-500 italic">
                                No Learning Objectives tracked yet.
                            </div>
                         )}
                     </div>
                </div>
            )}
        </div>
      </div>
    </div>
  );
};

export default AnalyticsDashboard;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { UploadedFile, ExamQuestion, ExamAttempt, Project, DifficultyLevel, BlueprintSection } from './types';
import FileUpload from './components/FileUpload';
import QuestionCard from './components/QuestionCard';
import AnalyticsDashboard from './components/AnalyticsDashboard';
import ProjectList from './components/ProjectList';
import { generateExam } from './services/geminiService';
import { saveProject, getAllProjects, deleteProject } from './services/storageService';
import { Stethoscope, Loader2, Key, ChevronDown, ChevronUp, Download, ArrowRight, AlertTriangle, History, CheckCheck, BarChart2, Layout, ArrowLeft, SignalHigh, SignalMedium, SignalLow, Layers, Hash, Printer, Lock, MessageSquare, Send, X } from 'lucide-react';
import { useReactToPrint } from 'react-to-print';

// --- CONFIGURATION ---
const BETA_PASSWORD = "medbeta"; // Change this to your desired password
const FEEDBACK_EMAIL = "your-email@example.com"; // Change this to your email

function App() {
  // --- Auth State ---
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [passwordInput, setPasswordInput] = useState('');
  const [authError, setAuthError] = useState(false);
  const [showFeedback, setShowFeedback] = useState(false);
  const [feedbackText, setFeedbackText] = useState('');

  // --- Global State ---
  const [projects, setProjects] = useState<Project[]>([]);
  const [activeProject, setActiveProject] = useState<Project | null>(null);
  const [loadingProjects, setLoadingProjects] = useState(true);

  // --- UI State (Local to session) ---
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<'exam' | 'analytics'>('exam');

  // --- Initialization ---
  useEffect(() => {
    // Check session storage to keep user logged in on refresh
    const sessionAuth = sessionStorage.getItem('medexam_auth');
    if (sessionAuth === 'true') {
        setIsAuthenticated(true);
        loadProjects();
    } else {
        setLoadingProjects(false);
    }
  }, []);

  const handleLogin = (e: React.FormEvent) => {
      e.preventDefault();
      if (passwordInput === BETA_PASSWORD) {
          setIsAuthenticated(true);
          sessionStorage.setItem('medexam_auth', 'true');
          loadProjects();
      } else {
          setAuthError(true);
      }
  };

  const handleFeedbackSubmit = () => {
      const subject = encodeURIComponent("MedExam Beta Feedback");
      const body = encodeURIComponent(feedbackText);
      window.open(`mailto:${FEEDBACK_EMAIL}?subject=${subject}&body=${body}`);
      setShowFeedback(false);
      setFeedbackText('');
  };

  const loadProjects = async () => {
    setLoadingProjects(true);
    const loadedProjects = await getAllProjects();
    setProjects(loadedProjects);
    setLoadingProjects(false);
  };

  const handleCreateProject = async (name: string, description: string, blueprint: BlueprintSection[], referenceTotal: number) => {
    const newProject: Project = {
        id: crypto.randomUUID(),
        name,
        description,
        lastModified: new Date().toISOString(),
        referenceTotalQuestions: referenceTotal,
        learningObjectivesFiles: [],
        blueprint: blueprint,
        examHistory: [],
        activeExam: {
            questions: [],
            userAnswers: {},
            status: 'active',
            configOpen: true,
            questionCount: 10,
            difficulty: 'standard'
        }
    };
    await saveProject(newProject);
    setProjects(prev => [newProject, ...prev]);
    setActiveProject(newProject);
  };

  const handleDeleteProject = async (id: string) => {
    await deleteProject(id);
    setProjects(prev => prev.filter(p => p.id !== id));
    if (activeProject?.id === id) setActiveProject(null);
  };

  const updateActiveProject = useCallback(async (updatedProject: Project) => {
    setActiveProject(updatedProject);
    setProjects(prev => prev.map(p => p.id === updatedProject.id ? updatedProject : p));
    await saveProject(updatedProject);
  }, []);

  // --- Project Specific Handlers ---

  const handleLoFilesChange = (files: UploadedFile[]) => {
    if (!activeProject) return;
    updateActiveProject({ ...activeProject, learningObjectivesFiles: files });
  };

  // Handle uploading files to a specific bucket/section
  const handleSectionFilesChange = (sectionId: string, files: UploadedFile[]) => {
    if (!activeProject) return;
    const updatedBlueprint = activeProject.blueprint.map(section => 
        section.id === sectionId ? { ...section, files } : section
    );
    updateActiveProject({ ...activeProject, blueprint: updatedBlueprint });
  };

  const handleQuestionCountChange = (count: number) => {
      if (!activeProject) return;
      updateActiveProject({
          ...activeProject,
          activeExam: { ...activeProject.activeExam, questionCount: count }
      });
  };

  const handleDifficultyChange = (level: DifficultyLevel) => {
    if (!activeProject) return;
    updateActiveProject({
        ...activeProject,
        activeExam: { ...activeProject.activeExam, difficulty: level }
    });
  };

  const handleConfigToggle = () => {
      if (!activeProject) return;
      updateActiveProject({
          ...activeProject,
          activeExam: { ...activeProject.activeExam, configOpen: !activeProject.activeExam.configOpen }
      });
  };

  const handleGenerate = async () => {
    if (!activeProject) return;

    // Validate that at least some content exists
    const hasLOs = activeProject.learningObjectivesFiles.length > 0;
    const hasContent = activeProject.blueprint.some(s => s.files.length > 0);

    if (!hasLOs && !hasContent) {
      setError("Please upload at least one file (Learning Objectives or Content in a Section).");
      return;
    }

    setLoading(true);
    setError(null);

    const resetExamState = {
        ...activeProject.activeExam,
        questions: [],
        userAnswers: {},
        status: 'active' as const,
        configOpen: false
    };
    setActiveProject({ ...activeProject, activeExam: resetExamState });

    try {
      const generatedQuestions = await generateExam(
          activeProject.learningObjectivesFiles, 
          activeProject.blueprint, 
          activeProject.activeExam.questionCount,
          activeProject.activeExam.difficulty || 'standard',
          activeProject.referenceTotalQuestions || 40 // Pass the reference total
      );

      const newExamState = {
          ...resetExamState,
          questions: generatedQuestions
      };

      updateActiveProject({ ...activeProject, activeExam: newExamState });
      setActiveTab('exam');
    } catch (err: any) {
      setError(err.message || "Failed to generate exam. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const handleOptionSelect = (questionId: number, option: string) => {
    if (!activeProject) return;
    const updatedAnswers = {
        ...activeProject.activeExam.userAnswers,
        [questionId]: option
    };
    updateActiveProject({
        ...activeProject,
        activeExam: { ...activeProject.activeExam, userAnswers: updatedAnswers }
    });
  };

  const handleUpdateQuestion = (updatedQuestion: ExamQuestion) => {
    if (!activeProject) return;
    const updatedQuestions = activeProject.activeExam.questions.map(q => 
        q.id === updatedQuestion.id ? updatedQuestion : q
    );
    updateActiveProject({
        ...activeProject,
        activeExam: { ...activeProject.activeExam, questions: updatedQuestions }
    });
  };

  const calculateScore = () => {
    if (!activeProject) return 0;
    let score = 0;
    activeProject.activeExam.questions.forEach(q => {
        if (activeProject.activeExam.userAnswers[q.id] === q.correctAnswer) {
            score++;
        }
    });
    return score;
  };

  const handleFinishExam = () => {
    if (!activeProject || activeProject.activeExam.questions.length === 0) return;
    const { questions, userAnswers } = activeProject.activeExam;

    if (Object.keys(userAnswers).length < questions.length) {
        if (!window.confirm(`You have answered ${Object.keys(userAnswers).length} out of ${questions.length} questions. Are you sure you want to submit?`)) {
            return;
        }
    }

    const finalScore = calculateScore();
    const attempt: ExamAttempt = {
        id: crypto.randomUUID(),
        date: new Date().toISOString(),
        score: finalScore,
        totalQuestions: questions.length,
        answers: { ...userAnswers },
        questions: [ ...questions ]
    };

    updateActiveProject({
        ...activeProject,
        examHistory: [...activeProject.examHistory, attempt],
        activeExam: { ...activeProject.activeExam, status: 'completed' }
    });

    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handlePrint = () => {
    window.print();
  };

  const handleDownload = () => {
    if (!activeProject) return;
    const { questions, userAnswers } = activeProject.activeExam;
    const content = questions.map((q, i) => `
Q${i+1}. ${q.vignette}
${q.leadIn}
A. ${q.options.A}
B. ${q.options.B}
C. ${q.options.C}
D. ${q.options.D}

User Answer: ${userAnswers[q.id] || "Skipped"}
Correct: ${q.correctAnswer}
Explanation: ${q.explanation}
Metadata: [${q.metadata.cognitiveLevel}, ${q.metadata.cluster}]
`).join('\n---\n');

    const blob = new Blob([content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${activeProject.name.replace(/\s+/g, '_')}_Exam_${new Date().toISOString().slice(0,10)}.txt`;
    a.click();
    URL.revokeObjectURL(url);
  };

  // --- BETA AUTH VIEW ---
  if (!isAuthenticated) {
      return (
        <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
            <div className="bg-white max-w-md w-full p-8 rounded-2xl shadow-xl border border-slate-100">
                <div className="flex justify-center mb-6">
                    <div className="bg-blue-600 p-3 rounded-xl shadow-lg shadow-blue-200">
                        <Stethoscope className="w-8 h-8 text-white" />
                    </div>
                </div>
                <h1 className="text-2xl font-bold text-center text-slate-900 mb-2">MedExam Generator</h1>
                <div className="flex justify-center mb-8">
                     <span className="bg-blue-100 text-blue-700 text-xs font-bold px-3 py-1 rounded-full uppercase tracking-wider">Beta Access</span>
                </div>

                <form onSubmit={handleLogin} className="space-y-4">
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">Access Password</label>
                        <div className="relative">
                            <input 
                                type="password" 
                                value={passwordInput}
                                onChange={(e) => {
                                    setPasswordInput(e.target.value);
                                    setAuthError(false);
                                }}
                                className={`w-full px-4 py-3 border rounded-xl outline-none focus:ring-2 transition-all ${authError ? 'border-red-300 focus:ring-red-200' : 'border-slate-200 focus:ring-blue-500 focus:border-blue-500'}`}
                                placeholder="Enter beta password"
                            />
                            <Lock className="w-5 h-5 text-slate-400 absolute right-3 top-3.5" />
                        </div>
                        {authError && <p className="text-red-500 text-sm mt-1 ml-1">Incorrect password</p>}
                    </div>
                    <button 
                        type="submit"
                        className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 rounded-xl transition-all shadow-md hover:shadow-lg transform active:scale-95"
                    >
                        Enter App
                    </button>
                </form>
                <p className="text-center text-slate-400 text-xs mt-6">
                    Restricted usage for testing purposes only.
                </p>
            </div>
        </div>
      );
  }

  if (loadingProjects) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50">
        <Loader2 className="w-8 h-8 text-blue-600 animate-spin" />
      </div>
    );
  }

  // --- FEEDBACK MODAL ---
  const FeedbackModal = () => (
      <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4 animate-fadeIn">
          <div className="bg-white rounded-xl shadow-2xl max-w-md w-full p-6 relative">
              <button 
                onClick={() => setShowFeedback(false)}
                className="absolute top-4 right-4 text-slate-400 hover:text-slate-600"
              >
                  <X className="w-5 h-5" />
              </button>
              <h3 className="text-xl font-bold text-slate-900 mb-4 flex items-center gap-2">
                  <MessageSquare className="w-5 h-5 text-blue-600" /> Beta Feedback
              </h3>
              <p className="text-sm text-slate-500 mb-4">
                  Found a bug or have an idea? Let us know! This will open your default email client.
              </p>
              <textarea 
                  value={feedbackText}
                  onChange={(e) => setFeedbackText(e.target.value)}
                  placeholder="Describe your issue or suggestion..."
                  className="w-full h-32 p-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none resize-none mb-4 text-sm"
              />
              <button 
                  onClick={handleFeedbackSubmit}
                  disabled={!feedbackText.trim()}
                  className="w-full bg-blue-600 hover:bg-blue-700 disabled:bg-slate-300 disabled:cursor-not-allowed text-white font-bold py-2 rounded-lg flex items-center justify-center gap-2"
              >
                  <Send className="w-4 h-4" /> Send Feedback
              </button>
          </div>
      </div>
  );

  // --- VIEW: PROJECT LIST ---
  if (!activeProject) {
      return (
          <div className="min-h-screen bg-slate-50">
             <header className="bg-white border-b border-slate-200 shadow-sm">
                <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
                    <div className="flex items-center space-x-3">
                        <div className="bg-blue-600 p-2 rounded-lg">
                            <Stethoscope className="w-5 h-5 text-white" />
                        </div>
                        <h1 className="text-xl font-bold text-slate-900 tracking-tight">MedExam Generator</h1>
                        <span className="bg-blue-100 text-blue-800 text-[10px] font-bold px-2 py-0.5 rounded uppercase">Beta</span>
                    </div>
                </div>
            </header>
            <ProjectList 
                projects={projects} 
                onSelectProject={setActiveProject}
                onCreateProject={handleCreateProject}
                onDeleteProject={handleDeleteProject}
            />

            {/* Feedback Button */}
            <button 
                onClick={() => setShowFeedback(true)}
                className="fixed bottom-6 right-6 bg-slate-900 hover:bg-slate-800 text-white p-4 rounded-full shadow-lg hover:shadow-xl transition-all z-40 flex items-center gap-2 group"
            >
                <MessageSquare className="w-6 h-6" />
                <span className="max-w-0 overflow-hidden group-hover:max-w-xs transition-all duration-300 whitespace-nowrap font-medium text-sm">Feedback</span>
            </button>
            {showFeedback && <FeedbackModal />}
          </div>
      );
  }

  // --- VIEW: PROJECT WORKSPACE ---
  const { activeExam, learningObjectivesFiles, blueprint, examHistory } = activeProject;
  const currentDifficulty = activeExam.difficulty || 'standard';

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col print:bg-white">
      {/* Header - Hidden in Print */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-20 shadow-sm print:hidden">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-4">
             <button 
                onClick={() => setActiveProject(null)}
                className="p-2 -ml-2 text-slate-500 hover:text-blue-600 hover:bg-slate-100 rounded-lg transition-colors"
                title="Back to Projects"
             >
                 <ArrowLeft className="w-5 h-5" />
             </button>
             <div className="h-6 w-px bg-slate-200 mx-1"></div>
             <div>
                <h1 className="text-lg font-bold text-slate-900 tracking-tight leading-tight">{activeProject.name}</h1>
                <p className="text-xs text-slate-500 hidden sm:block">Project Workspace</p>
             </div>
          </div>

          <div className="flex items-center gap-2">
            <nav className="flex items-center p-1 bg-slate-100 rounded-lg mr-2">
                <button 
                    onClick={() => setActiveTab('exam')}
                    className={`flex items-center gap-2 px-3 py-1.5 text-sm font-medium rounded-md transition-all ${activeTab === 'exam' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                >
                    <Layout className="w-4 h-4" /> <span className="hidden sm:inline">Exam</span>
                </button>
                <button 
                    onClick={() => setActiveTab('analytics')}
                    className={`flex items-center gap-2 px-3 py-1.5 text-sm font-medium rounded-md transition-all ${activeTab === 'analytics' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                >
                    <BarChart2 className="w-4 h-4" /> <span className="hidden sm:inline">Progress</span>
                </button>
            </nav>
          </div>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 py-8 w-full flex-grow print:max-w-none print:p-0">

        {activeTab === 'exam' && (
            <div className="flex items-center gap-2 mb-4 text-xs text-slate-500 justify-end print:hidden">
                <History className="w-3 h-3" />
                <span>Auto-saved</span>
            </div>
        )}

        {/* ANALYTICS TAB */}
        {activeTab === 'analytics' && (
            <div className="animate-fadeIn print:hidden">
                <h2 className="text-2xl font-bold text-slate-900 mb-6">Performance Analytics: {activeProject.name}</h2>
                <AnalyticsDashboard history={examHistory} />
            </div>
        )}

        {/* EXAM TAB */}
        {activeTab === 'exam' && (
        <>
            {/* Configuration Panel - Hidden in Print */}
            <div className={`bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden mb-8 transition-all duration-300 print:hidden ${!activeExam.configOpen && activeExam.questions.length > 0 ? 'opacity-80 hover:opacity-100' : ''}`}>
            <div 
                className="px-6 py-4 bg-slate-50 border-b border-slate-200 flex items-center justify-between cursor-pointer"
                onClick={handleConfigToggle}
            >
                <h2 className="font-semibold text-slate-900 flex items-center gap-2">
                    <Key className="w-4 h-4 text-slate-500" />
                    Generator Configuration
                </h2>
                {activeExam.configOpen ? <ChevronUp className="w-4 h-4 text-slate-500"/> : <ChevronDown className="w-4 h-4 text-slate-500"/>}
            </div>

            {activeExam.configOpen && (
