export default App;

import { Project } from '../types';

const DB_NAME = 'MedExamDB';
const DB_VERSION = 6; // Incremented for User Auth Store
const STORE_NAME = 'projects';
const USER_STORE = 'users';

const openDB = (): Promise<IDBDatabase> => {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, DB_VERSION);

    request.onerror = (event) => reject('Error opening database');

    request.onupgradeneeded = (event) => {
      const db = (event.target as IDBOpenDBRequest).result;

      // Create projects store if it doesn't exist
      if (!db.objectStoreNames.contains(STORE_NAME)) {
        db.createObjectStore(STORE_NAME, { keyPath: 'id' });
      }

      // Create users store for local auth
      if (!db.objectStoreNames.contains(USER_STORE)) {
        db.createObjectStore(USER_STORE, { keyPath: 'username' });
      }

      // Cleanup old stores if they exist (migration from v2)
      if (db.objectStoreNames.contains('app_state')) {
        db.deleteObjectStore('app_state');
      }
    };

    request.onsuccess = (event) => {
      resolve((event.target as IDBOpenDBRequest).result);
    };
  });
};

// --- USER AUTHENTICATION METHODS ---

export const registerUser = async (username: string, password: string): Promise<boolean> => {
  try {
    const db = await openDB();
    const transaction = db.transaction(USER_STORE, 'readwrite');
    const store = transaction.objectStore(USER_STORE);

    // Check if user exists
    const checkRequest = store.get(username);

    return new Promise((resolve, reject) => {
      checkRequest.onsuccess = () => {
        if (checkRequest.result) {
          // User already exists
          resolve(false); 
        } else {
          // Add new user
          store.add({ username, password, createdAt: new Date().toISOString() });
          resolve(true);
        }
      };
      checkRequest.onerror = () => reject(checkRequest.error);
    });
  } catch (error) {
    console.error('Registration failed:', error);
    return false;
  }
};

export const loginUser = async (username: string, password: string): Promise<boolean> => {
  try {
    const db = await openDB();
    const transaction = db.transaction(USER_STORE, 'readonly');
    const store = transaction.objectStore(USER_STORE);
    const request = store.get(username);

    return new Promise((resolve, reject) => {
      request.onsuccess = () => {
        const user = request.result;
        if (user && user.password === password) {
          resolve(true);
        } else {
          resolve(false);
        }
      };
      request.onerror = () => reject(request.error);
    });
  } catch (error) {
    console.error('Login failed:', error);
    return false;
  }
};

// --- PROJECT METHODS ---

export const saveProject = async (project: Project): Promise<void> => {
  try {
    const db = await openDB();
    const transaction = db.transaction(STORE_NAME, 'readwrite');
    const store = transaction.objectStore(STORE_NAME);

    // Update last modified
    const updatedProject = { ...project, lastModified: new Date().toISOString() };

    store.put(updatedProject);
    return new Promise((resolve, reject) => {
      transaction.oncomplete = () => resolve();
      transaction.onerror = () => reject(transaction.error);
    });
  } catch (error) {
    console.error(`Failed to save project ${project.id}:`, error);
  }
};

export const getAllProjects = async (userId: string): Promise<Project[]> => {
  try {
    const db = await openDB();
    const transaction = db.transaction(STORE_NAME, 'readonly');
    const store = transaction.objectStore(STORE_NAME);
    const request = store.getAll();

    return new Promise((resolve, reject) => {
      request.onsuccess = () => {
        const allProjects = request.result as Project[];
        const userProjects = allProjects.filter(p => p.userId === userId);

        // Sort by last modified descending
        userProjects.sort((a, b) => new Date(b.lastModified).getTime() - new Date(a.lastModified).getTime());
        resolve(userProjects);
      };
      request.onerror = () => reject(request.error);
    });
  } catch (error) {
    console.error('Failed to load projects:', error);
    return [];
  }
};

export const getProject = async (id: string): Promise<Project | null> => {
  try {
    const db = await openDB();
    const transaction = db.transaction(STORE_NAME, 'readonly');
    const store = transaction.objectStore(STORE_NAME);
    const request = store.get(id);

    return new Promise((resolve, reject) => {
      request.onsuccess = () => resolve(request.result as Project || null);
      request.onerror = () => reject(request.error);
    });
  } catch (error) {
    console.error(`Failed to load project ${id}:`, error);
    return null;
  }
};

export const deleteProject = async (id: string): Promise<void> => {
  try {
    const db = await openDB();
    const transaction = db.transaction(STORE_NAME, 'readwrite');
    const store = transaction.objectStore(STORE_NAME);
    store.delete(id);

    return new Promise((resolve, reject) => {
      transaction.oncomplete = () => resolve();
      transaction.onerror = () => reject(transaction.error);
    });
  } catch (error) {
    console.error('Failed to delete project:', error);
  }
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { UploadedFile, ExamQuestion, ExamAttempt, Project, DifficultyLevel, BlueprintSection } from './types';
import FileUpload from './components/FileUpload';
import QuestionCard from './components/QuestionCard';
import AnalyticsDashboard from './components/AnalyticsDashboard';
import ProjectList from './components/ProjectList';
import { generateExam } from './services/geminiService';
import { saveProject, getAllProjects, deleteProject, registerUser, loginUser } from './services/storageService';
import { logEvent, setTelemetryUser } from './services/telemetryService';
import { Stethoscope, Loader2, Key, ChevronDown, ChevronUp, Download, ArrowRight, AlertTriangle, History, CheckCheck, BarChart2, Layout, ArrowLeft, SignalHigh, SignalMedium, SignalLow, Layers, Hash, Printer, Lock, MessageSquare, Send, X, User, LogOut, ShieldCheck, UserPlus, LogIn } from 'lucide-react';
import { useReactToPrint } from 'react-to-print';

// --- CONFIGURATION ---
const BETA_INVITE_CODE = "medbeta"; 
const FEEDBACK_EMAIL = "your-email@example.com"; 

function App() {
  // --- Auth State ---
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [authMode, setAuthMode] = useState<'login' | 'register'>('login');

  // Auth Inputs
  const [usernameInput, setUsernameInput] = useState('');
  const [passwordInput, setPasswordInput] = useState('');
  const [inviteCodeInput, setInviteCodeInput] = useState('');

  const [currentUser, setCurrentUser] = useState<string | null>(null);
  const [isAdmin, setIsAdmin] = useState(false);

  const [authError, setAuthError] = useState<string | null>(null);
  const [authSuccess, setAuthSuccess] = useState<string | null>(null);
  const [showFeedback, setShowFeedback] = useState(false);
  const [feedbackText, setFeedbackText] = useState('');

  // --- Global State ---
  const [projects, setProjects] = useState<Project[]>([]);
  const [activeProject, setActiveProject] = useState<Project | null>(null);
  const [loadingProjects, setLoadingProjects] = useState(true);

  // --- UI State (Local to session) ---
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<'exam' | 'analytics'>('exam');

  // --- Initialization ---
  useEffect(() => {
    logEvent('session_start');

    // Check session storage
    const sessionAuth = sessionStorage.getItem('medexam_auth');
    const sessionUser = sessionStorage.getItem('medexam_user');

    if (sessionAuth === 'true' && sessionUser) {
        setIsAuthenticated(true);
        setCurrentUser(sessionUser);
        setTelemetryUser(sessionUser); // Initialize Telemetry

        if (sessionUser.toLowerCase() === 'admin') {
            setIsAdmin(true);
        }

        loadProjects(sessionUser);
    } else {
        setLoadingProjects(false);
    }
  }, []);

  const handleAuthSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setAuthError(null);
    setAuthSuccess(null);

    const user = usernameInput.trim();
    if (!user || !passwordInput) {
        setAuthError("Please fill in all fields.");
        return;
    }

    if (authMode === 'register') {
        if (inviteCodeInput !== BETA_INVITE_CODE) {
            setAuthError("Invalid Invite Code.");
            logEvent('beta_login_fail', { reason: 'invalid_invite_code' });
            return;
        }

        const success = await registerUser(user, passwordInput);
        if (success) {
            setAuthSuccess("Account created! Please sign in.");
            setAuthMode('login');
            setPasswordInput('');
            logEvent('user_registered', { username: user }); // Log registration
        } else {
            setAuthError("Username already taken.");
        }
    } else {
        // Login Mode
        const isValid = await loginUser(user, passwordInput);

        if (isValid) {
            completeLogin(user);
        } else {
            setAuthError("Invalid username or password.");
            logEvent('beta_login_fail', { reason: 'invalid_credentials', username: user });
        }
    }
  };

  const completeLogin = (user: string) => {
      setIsAuthenticated(true);
      setCurrentUser(user);
      setTelemetryUser(user);

      sessionStorage.setItem('medexam_auth', 'true');
      sessionStorage.setItem('medexam_user', user);

      if (user.toLowerCase() === 'admin') {
          setIsAdmin(true);
          logEvent('admin_action', { action: 'admin_login' });
      } else {
          logEvent('beta_login_success');
      }

      loadProjects(user);
  };

  const handleLogout = () => {
    logEvent('feature_used', { feature: 'logout' });
    setIsAuthenticated(false);
    setCurrentUser(null);
    setIsAdmin(false);
    setActiveProject(null);
    setTelemetryUser(null); 
    sessionStorage.removeItem('medexam_auth');
    sessionStorage.removeItem('medexam_user');
    setPasswordInput('');
    setUsernameInput('');
    setAuthError(null);
  };

  const handleFeedbackSubmit = () => {
      logEvent('feature_used', { feature: 'feedback_button' });
      const subject = encodeURIComponent("MedExam Beta Feedback");
      const body = encodeURIComponent(`User: ${currentUser}\n\n${feedbackText}`);
      window.open(`mailto:${FEEDBACK_EMAIL}?subject=${subject}&body=${body}`);
      setShowFeedback(false);
      setFeedbackText('');
  };

  const loadProjects = async (userId: string) => {
    setLoadingProjects(true);
    const loadedProjects = await getAllProjects(userId);
    setProjects(loadedProjects);
    setLoadingProjects(false);
  };

  const handleCreateProject = async (name: string, description: string, blueprint: BlueprintSection[], referenceTotal: number) => {
    if (!currentUser) return;

    logEvent('feature_used', { feature: 'create_project', referenceTotal });
    const newProject: Project = {
        id: crypto.randomUUID(),
        userId: currentUser,
        name,
        description,
        lastModified: new Date().toISOString(),
        referenceTotalQuestions: referenceTotal,
        learningObjectivesFiles: [],
        blueprint: blueprint,
        examHistory: [],
        activeExam: {
            questions: [],
            userAnswers: {},
            status: 'active',
            configOpen: true,
            questionCount: 10,
            difficulty: 'standard'
        }
    };
    await saveProject(newProject);
    setProjects(prev => [newProject, ...prev]);
    setActiveProject(newProject);
  };

  const handleDeleteProject = async (id: string) => {
    await deleteProject(id);
    setProjects(prev => prev.filter(p => p.id !== id));
    if (activeProject?.id === id) setActiveProject(null);
  };

  const updateActiveProject = useCallback(async (updatedProject: Project) => {
    setActiveProject(updatedProject);
    setProjects(prev => prev.map(p => p.id === updatedProject.id ? updatedProject : p));
    await saveProject(updatedProject);
  }, []);

  // --- Project Specific Handlers ---

  const handleLoFilesChange = (files: UploadedFile[]) => {
    if (!activeProject) return;
    updateActiveProject({ ...activeProject, learningObjectivesFiles: files });
  };

  // Handle uploading files to a specific bucket/section
  const handleSectionFilesChange = (sectionId: string, files: UploadedFile[]) => {
    if (!activeProject) return;
    const updatedBlueprint = activeProject.blueprint.map(section => 
        section.id === sectionId ? { ...section, files } : section
    );
    updateActiveProject({ ...activeProject, blueprint: updatedBlueprint });
  };

  const handleQuestionCountChange = (count: number) => {
      if (!activeProject) return;
      updateActiveProject({
          ...activeProject,
          activeExam: { ...activeProject.activeExam, questionCount: count }
      });
  };

  const handleDifficultyChange = (level: DifficultyLevel) => {
    if (!activeProject) return;
    updateActiveProject({
        ...activeProject,
        activeExam: { ...activeProject.activeExam, difficulty: level }
    });
  };

  const handleConfigToggle = () => {
      if (!activeProject) return;
      updateActiveProject({
          ...activeProject,
          activeExam: { ...activeProject.activeExam, configOpen: !activeProject.activeExam.configOpen }
      });
  };

  const handleGenerate = async () => {
    if (!activeProject) return;

    // Validate that at least some content exists
    const hasLOs = activeProject.learningObjectivesFiles.length > 0;
    const hasContent = activeProject.blueprint.some(s => s.files.length > 0);

    if (!hasLOs && !hasContent) {
      setError("Please upload at least one file (Learning Objectives or Content in a Section).");
      return;
    }

    setLoading(true);
    setError(null);

    // Telemetry: Log generation attempt
    logEvent('exam_generated', {
        questionCount: activeProject.activeExam.questionCount,
        difficulty: activeProject.activeExam.difficulty,
        blueprintSections: activeProject.blueprint.length,
        totalFiles: activeProject.learningObjectivesFiles.length + activeProject.blueprint.reduce((acc, s) => acc + s.files.length, 0)
    });

    const resetExamState = {
        ...activeProject.activeExam,
        questions: [],
        userAnswers: {},
        status: 'active' as const,
        configOpen: false
    };
    setActiveProject({ ...activeProject, activeExam: resetExamState });

    try {
      const generatedQuestions = await generateExam(
          activeProject.learningObjectivesFiles, 
          activeProject.blueprint, 
          activeProject.activeExam.questionCount,
          activeProject.activeExam.difficulty || 'standard',
          activeProject.referenceTotalQuestions || 40 // Pass the reference total
      );

      const newExamState = {
          ...resetExamState,
          questions: generatedQuestions
      };

      updateActiveProject({ ...activeProject, activeExam: newExamState });
      setActiveTab('exam');
    } catch (err: any) {
      setError(err.message || "Failed to generate exam. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const handleOptionSelect = (questionId: number, option: string) => {
    if (!activeProject) return;
    const updatedAnswers = {
        ...activeProject.activeExam.userAnswers,
        [questionId]: option
    };
    updateActiveProject({
        ...activeProject,
        activeExam: { ...activeProject.activeExam, userAnswers: updatedAnswers }
    });
  };

  const handleUpdateQuestion = (updatedQuestion: ExamQuestion) => {
    if (!activeProject) return;
    const updatedQuestions = activeProject.activeExam.questions.map(q => 
        q.id === updatedQuestion.id ? updatedQuestion : q
    );
    updateActiveProject({
        ...activeProject,
        activeExam: { ...activeProject.activeExam, questions: updatedQuestions }
    });
  };

  const calculateScore = () => {
    if (!activeProject) return 0;
    let score = 0;
    activeProject.activeExam.questions.forEach(q => {
        if (activeProject.activeExam.userAnswers[q.id] === q.correctAnswer) {
            score++;
        }
    });
    return score;
  };

  const handleFinishExam = () => {
    if (!activeProject || activeProject.activeExam.questions.length === 0) return;
    const { questions, userAnswers } = activeProject.activeExam;

    if (Object.keys(userAnswers).length < questions.length) {
        if (!window.confirm(`You have answered ${Object.keys(userAnswers).length} out of ${questions.length} questions. Are you sure you want to submit?`)) {
            return;
        }
    }

    const finalScore = calculateScore();
    const attempt: ExamAttempt = {
        id: crypto.randomUUID(),
        date: new Date().toISOString(),
        score: finalScore,
        totalQuestions: questions.length,
        answers: { ...userAnswers },
        questions: [ ...questions ]
    };

    // Telemetry: Log completion
    logEvent('exam_completed', {
        score: finalScore,
        totalQuestions: questions.length,
        percentage: Math.round((finalScore / questions.length) * 100),
        difficulty: activeProject.activeExam.difficulty
    });

    updateActiveProject({
        ...activeProject,
        examHistory: [...activeProject.examHistory, attempt],
        activeExam: { ...activeProject.activeExam, status: 'completed' }
    });

    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handlePrint = () => {
    logEvent('feature_used', { feature: 'print' });
