                 <div className="hidden print:block w-full text-center mb-8 border-b-2 border-black pb-4">
                     <h1 className="text-3xl font-bold text-black">{activeProject.name} - Practice Exam</h1>
                     <p className="text-gray-600 mt-2">Questions: {activeExam.questions.length} | Difficulty: {activeExam.difficulty?.toUpperCase() || 'STANDARD'}</p>
                 </div>

                 <div className="flex items-center gap-3 print:hidden">
                    <button
                        onClick={handlePrint}
                        className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-slate-700 bg-white border border-slate-200 hover:bg-slate-50 rounded-lg transition-colors shadow-sm"
                    >
                        <Printer className="w-4 h-4" /> Print
                    </button>
                    {activeExam.status === 'completed' && (
                        <button
                        onClick={handleDownload}
                        className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-slate-700 bg-white border border-slate-200 hover:bg-slate-50 rounded-lg transition-colors shadow-sm"
                        >
                            <Download className="w-4 h-4" /> Export
                        </button>
                     )}

                     {activeExam.status === 'active' && (
                         <button
                         onClick={handleFinishExam}
                         className="flex items-center gap-2 px-6 py-2 text-sm font-bold text-white bg-green-600 hover:bg-green-700 rounded-lg transition-colors shadow-sm hover:shadow"
                         >
                             <CheckCheck className="w-4 h-4" /> Finish Exam
                         </button>
                     )}
                 </div>
            </div>
            )}

            {/* Question List */}
            {activeExam.questions.length > 0 && (
            <div className="space-y-6 animate-slideUp print:space-y-8">
                {activeExam.questions.map((q, index) => (
                <QuestionCard 
                    key={q.id || index} 
                    question={q} 
                    index={index} 
                    selectedOption={activeExam.userAnswers[q.id] || null}
                    onSelectOption={(opt) => handleOptionSelect(q.id, opt)}
                    onUpdateQuestion={handleUpdateQuestion}
                    isSubmitted={activeExam.status === 'completed'}
                />
                ))}

                {/* Answer Key for Print */}
                <div className="hidden print:block break-before-page">
                    <h2 className="text-2xl font-bold mb-6 border-b-2 border-black pb-2">Answer Key & Explanations</h2>
                    <div className="space-y-6">
                        {activeExam.questions.map((q, i) => (
                            <div key={i} className="mb-4">
                                <div className="font-bold text-lg mb-1">Question {i+1}: <span className="text-black">{q.correctAnswer}</span></div>
                                <p className="text-sm text-gray-700">{q.explanation}</p>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Bottom Finish Button (if long exam) */}
                {activeExam.questions.length > 3 && activeExam.status === 'active' && (
                    <div className="flex justify-center pt-8 pb-12 print:hidden">
                         <button
                         onClick={handleFinishExam}
                         className="flex items-center gap-2 px-8 py-4 text-lg font-bold text-white bg-green-600 hover:bg-green-700 rounded-xl transition-all shadow-md hover:shadow-lg hover:-translate-y-0.5"
                         >
                             <CheckCheck className="w-5 h-5" /> Finish & Submit Exam
                         </button>
                    </div>
                )}
            </div>
            )}

            {/* Empty State */}
            {!loading && activeExam.questions.length === 0 && !activeExam.configOpen && (
                <div className="text-center py-12 bg-slate-50 rounded-xl border border-dashed border-slate-300 print:hidden">
                    <p className="text-slate-500 font-medium">Exam generation complete or pending. <button onClick={handleConfigToggle} className="text-blue-600 hover:underline">Open configuration</button> to start.</p>
                </div>
            )}
        </>
        )}
      </main>

      {/* Floating Feedback Button (Project View) */}
      {!isAdmin && (
        <button 
            onClick={() => setShowFeedback(true)}
            className="fixed bottom-6 right-6 bg-slate-900 hover:bg-slate-800 text-white p-4 rounded-full shadow-lg hover:shadow-xl transition-all z-40 flex items-center gap-2 group print:hidden"
        >
            <MessageSquare className="w-6 h-6" />
            <span className="max-w-0 overflow-hidden group-hover:max-w-xs transition-all duration-300 whitespace-nowrap font-medium text-sm">Feedback</span>
        </button>
      )}
      {showFeedback && <FeedbackModal />}
    </div>
  );
}

export default App;

import React, { useState, useRef } from 'react';
import { Project, BlueprintSection } from '../types';
import { Plus, FolderOpen, Calendar, Trash2, FileText, ArrowRight, X, PieChart, Hash, Share2, Upload, DownloadCloud } from 'lucide-react';

interface ProjectListProps {
  projects: Project[];
  onSelectProject: (project: Project) => void;
  onCreateProject: (name: string, description: string, blueprint: BlueprintSection[], referenceTotal: number) => void;
  onDeleteProject: (id: string) => void;
  onImportProject: (data: any) => void; // New prop
}

const ProjectList: React.FC<ProjectListProps> = ({ projects, onSelectProject, onCreateProject, onDeleteProject, onImportProject }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [newName, setNewName] = useState('');
  const [newDesc, setNewDesc] = useState('');
  const [referenceTotal, setReferenceTotal] = useState<number>(40);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Blueprint Builder State
  const [sections, setSections] = useState<BlueprintSection[]>([
      { id: '1', title: 'Week 1 Content', description: 'Core material', questionCount: '10-12', files: [] }
  ]);

  const addSection = () => {
      setSections([...sections, { 
          id: crypto.randomUUID(), 
          title: '', 
          description: '', 
          questionCount: '', 
          files: [] 
      }]);
  };

  const removeSection = (id: string) => {
      if (sections.length > 1) {
          setSections(sections.filter(s => s.id !== id));
      }
  };

  const updateSection = (id: string, field: keyof BlueprintSection, value: string) => {
      setSections(sections.map(s => s.id === id ? { ...s, [field]: value } : s));
  };

  const handleCreate = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newName.trim()) return;
    if (referenceTotal <= 0) {
        alert("Please enter a valid reference total number of questions.");
        return;
    }
    onCreateProject(newName, newDesc, sections, referenceTotal);
    setNewName('');
    setNewDesc('');
    setReferenceTotal(40);
    setSections([{ id: '1', title: 'Week 1 Content', description: 'Core material', questionCount: '10-12', files: [] }]);
    setIsCreating(false);
  };

  const handleExport = (e: React.MouseEvent, project: Project) => {
    e.stopPropagation(); // Prevent opening the project

    // Create a downloadable version of the project
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(project));
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", `${project.name.replace(/\s+/g, '_')}_Project.medexam`);
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  const handleImportClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);
        onImportProject(json);
      } catch (err) {
        alert("Failed to parse project file.");
      }
    };
    reader.readAsText(file);
    // Reset input
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 py-12 animate-fadeIn">
      <div className="flex justify-between items-end mb-8">
        <div>
          <h2 className="text-3xl font-bold text-slate-900">Your Projects</h2>
          <p className="text-slate-500 mt-1">Manage your exam generation workspaces</p>
        </div>
        <div className="flex gap-2">
            <button
                onClick={handleImportClick}
                className="flex items-center gap-2 px-4 py-2 bg-white text-slate-700 border border-slate-300 rounded-lg hover:bg-slate-50 transition-colors shadow-sm font-medium"
            >
                <Upload className="w-5 h-5" /> Import
            </button>
            <input 
                type="file" 
                ref={fileInputRef} 
                className="hidden" 
                accept=".medexam,.json" 
                onChange={handleFileChange}
            />

            <button
            onClick={() => setIsCreating(true)}
            className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors shadow-sm font-medium"
            >
            <Plus className="w-5 h-5" /> New Project
            </button>
        </div>
      </div>

      {isCreating && (
        <div className="mb-8 bg-white p-6 rounded-xl border border-blue-100 shadow-md animate-slideUp">
          <h3 className="text-lg font-bold text-slate-900 mb-4">Create New Project</h3>
          <form onSubmit={handleCreate} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Project Name</label>
                <input
                    type="text"
                    value={newName}
                    onChange={(e) => setNewName(e.target.value)}
                    placeholder="e.g., Neurology Block"
                    className="w-full px-4 py-2 bg-white text-slate-900 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none"
                    autoFocus
                    required
                />
                </div>
                <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Description</label>
                <input
                    type="text"
                    value={newDesc}
                    onChange={(e) => setNewDesc(e.target.value)}
                    placeholder="Optional description"
                    className="w-full px-4 py-2 bg-white text-slate-900 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none"
                />
                </div>
            </div>

            <div className="border-t border-slate-100 pt-4">
                <div className="flex flex-col md:flex-row md:items-center justify-between mb-4 gap-4">
                    <label className="text-sm font-bold text-slate-800 flex items-center gap-2">
                        <PieChart className="w-4 h-4" /> Exam Blueprint
                    </label>
                    <div className="flex items-center gap-2 bg-blue-50 px-3 py-1.5 rounded-lg border border-blue-100">
                        <span className="text-sm text-blue-800 font-medium">Reference Total Questions:</span>
                        <input 
                            type="number"
                            min="1"
                            value={referenceTotal}
                            onChange={(e) => setReferenceTotal(parseInt(e.target.value) || 0)}
                            className="w-16 px-2 py-1 bg-white text-sm font-bold text-center border border-blue-200 rounded text-blue-900 focus:ring-2 focus:ring-blue-500 outline-none"
                        />
                    </div>
                </div>

                <p className="text-xs text-slate-500 mb-3">
                    Define your exam sections. For each section, specify the number of questions (e.g. "10") or a range (e.g. "10-12") based on your reference total above.
                </p>

                <div className="space-y-3">
                    {sections.map((section, idx) => (
                        <div key={section.id} className="flex flex-col md:flex-row gap-3 items-start md:items-center bg-slate-50 p-3 rounded-lg border border-slate-200">
                             <div className="flex-1 w-full">
                                <label className="block text-[10px] text-slate-400 font-bold uppercase mb-1 md:hidden">Section Name</label>
                                <input
                                    type="text"
                                    value={section.title}
                                    onChange={(e) => updateSection(section.id, 'title', e.target.value)}
                                    placeholder={`Section ${idx + 1} Name`}
                                    className="w-full px-3 py-1.5 bg-white text-slate-900 text-sm border border-slate-300 rounded focus:border-blue-500 outline-none"
                                    required
                                />
                             </div>
                             <div className="flex-1 w-full">
                                <label className="block text-[10px] text-slate-400 font-bold uppercase mb-1 md:hidden">Description</label>
                                <input
                                    type="text"
                                    value={section.description}
                                    onChange={(e) => updateSection(section.id, 'description', e.target.value)}
                                    placeholder="Brief content description"
                                    className="w-full px-3 py-1.5 bg-white text-slate-900 text-sm border border-slate-300 rounded focus:border-blue-500 outline-none"
                                />
                             </div>
                             <div className="w-full md:w-32">
                                <label className="block text-[10px] text-slate-400 font-bold uppercase mb-1 md:hidden">Questions</label>
                                <div className="relative">
                                    <input
                                        type="text"
                                        value={section.questionCount}
                                        onChange={(e) => updateSection(section.id, 'questionCount', e.target.value)}
                                        placeholder="e.g. 10-12"
                                        className="w-full px-3 py-1.5 bg-white text-slate-900 text-sm border border-slate-300 rounded focus:border-blue-500 outline-none pl-7"
                                        required
                                    />
                                    <Hash className="w-3 h-3 text-slate-400 absolute left-2.5 top-2" />
                                </div>
                             </div>
                             {sections.length > 1 && (
                                 <button 
                                    type="button" 
                                    onClick={() => removeSection(section.id)}
                                    className="p-1.5 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded mt-5 md:mt-0"
                                 >
                                     <X className="w-4 h-4" />
                                 </button>
                             )}
                        </div>
                    ))}
                </div>
                <button
                    type="button"
                    onClick={addSection}
                    className="mt-3 text-sm text-blue-600 font-medium hover:text-blue-800 flex items-center gap-1"
                >
                    <Plus className="w-4 h-4" /> Add Section
                </button>
            </div>

            <div className="flex gap-3 pt-4">
              <button
                type="submit"
                className="px-4 py-2 bg-blue-600 hover:bg-blue-700 rounded-lg font-medium text-white shadow-sm"
              >
                Create Project
              </button>
              <button
                type="button"
                onClick={() => setIsCreating(false)}
                className="px-4 py-2 bg-white text-slate-700 border border-slate-300 rounded-lg hover:bg-slate-50 font-medium"
              >
                Cancel
              </button>
            </div>
          </form>
        </div>
      )}

      {projects.length === 0 && !isCreating ? (
        <div className="text-center py-20 bg-slate-50 rounded-xl border-2 border-dashed border-slate-200">
          <FolderOpen className="w-12 h-12 text-slate-300 mx-auto mb-4" />
          <h3 className="text-lg font-medium text-slate-900">No projects yet</h3>
          <p className="text-slate-500 mt-1 mb-6">Create a project or Import one to start generating exams.</p>
          <div className="flex justify-center gap-4">
              <button
                onClick={() => setIsCreating(true)}
                className="inline-flex items-center gap-2 px-5 py-2.5 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors shadow-sm font-medium"
              >
                <Plus className="w-5 h-5" /> Create First Project
              </button>
              <button
                onClick={handleImportClick}
                className="inline-flex items-center gap-2 px-5 py-2.5 bg-white text-slate-700 border border-slate-300 rounded-lg hover:bg-slate-50 transition-colors shadow-sm font-medium"
              >
                <DownloadCloud className="w-5 h-5" /> Import
              </button>
          </div>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {projects.map((project) => (
            <div
              key={project.id}
              className="group bg-white rounded-xl border border-slate-200 shadow-sm hover:shadow-md hover:border-blue-200 transition-all duration-200 flex flex-col"
            >
              <div 
                className="p-6 cursor-pointer flex-grow"
                onClick={() => onSelectProject(project)}
              >
                <div className="flex justify-between items-start mb-4">
                  <div className="p-3 bg-blue-50 rounded-lg group-hover:bg-blue-100 transition-colors">
                    <FolderOpen className="w-6 h-6 text-blue-600" />
                  </div>
                  <span className="text-[10px] font-bold bg-slate-100 text-slate-600 px-2 py-1 rounded-md border border-slate-200">
                      Ref Total: {project.referenceTotalQuestions || 40}
                  </span>
                </div>

                <h3 className="text-xl font-bold text-slate-900 mb-2 group-hover:text-blue-600 transition-colors">
                  {project.name}
                </h3>
                <p className="text-sm text-slate-500 mb-4 line-clamp-2 min-h-[1.5rem]">
                  {project.description || "No description provided."}
                </p>

                {/* Blueprint Badges */}
                <div className="flex flex-wrap gap-2 mb-6">
                    {project.blueprint.slice(0, 3).map(section => (
                        <span key={section.id} className="text-[10px] bg-slate-100 text-slate-600 px-2 py-0.5 rounded-full border border-slate-200">
                            {section.title} ({section.questionCount})
                        </span>
                    ))}
                    {project.blueprint.length > 3 && <span className="text-[10px] text-slate-400">+{project.blueprint.length - 3} more</span>}
                </div>

                <div className="flex items-center gap-4 text-xs text-slate-400 mb-4">
                  <div className="flex items-center gap-1">
                    <FileText className="w-3 h-3" />
                    <span>
                        {project.learningObjectivesFiles.length + project.blueprint.reduce((acc, s) => acc + s.files.length, 0)} Files
                    </span>
                  </div>
                   <div className="flex items-center gap-1">
                    <Calendar className="w-3 h-3" />
                    <span>{new Date(project.lastModified).toLocaleDateString()}</span>
                  </div>
                </div>

                 {/* Mini Progress Bar */}
                 {project.examHistory.length > 0 && (
                    <div className="mb-2">
                        <div className="flex justify-between text-xs mb-1">
                            <span className="font-medium text-slate-600">Avg Score</span>
                            <span className="text-slate-500">
                                {Math.round(project.examHistory.reduce((acc, curr) => acc + (curr.score/curr.totalQuestions), 0) / project.examHistory.length * 100)}%
                            </span>
                        </div>
                        <div className="w-full bg-slate-100 rounded-full h-1.5">
                            <div 
                                className="bg-green-500 h-1.5 rounded-full" 
                                style={{ width: `${Math.round(project.examHistory.reduce((acc, curr) => acc + (curr.score/curr.totalQuestions), 0) / project.examHistory.length * 100)}%`}}
                            ></div>
                        </div>
                    </div>
                 )}
              </div>

              <div className="px-6 py-4 border-t border-slate-100 bg-slate-50/50 rounded-b-xl flex items-center justify-between">
                <button
                    onClick={() => onSelectProject(project)}
                    className="text-sm font-semibold text-blue-600 hover:text-blue-800 flex items-center gap-1"
                >
                    Open <ArrowRight className="w-4 h-4" />
                </button>

                <div className="flex gap-2">
                    <button
                        onClick={(e) => handleExport(e, project)}
                        className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-full transition-colors"
                        title="Share / Export Project"
                    >
                        <Share2 className="w-4 h-4" />
                    </button>
                    <button
                    onClick={(e) => {
                        e.stopPropagation();
                        if(window.confirm(`Delete "${project.name}"? This cannot be undone.`)) {
                            onDeleteProject(project.id);
                        }
                    }}
                    className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-full transition-colors"
                    title="Delete Project"
                    >
                        <Trash2 className="w-4 h-4" />
                    </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default ProjectList;

