import { GoogleGenAI, Type } from "@google/genai";
import { SYSTEM_INSTRUCTION_BASE } from '../constants';
import { UploadedFile, ExamQuestion, DifficultyLevel, BlueprintSection } from '../types';

// New function for OCR
export const extractTextFromImage = async (base64Data: string, mimeType: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  // Removed try-catch to allow error propagation to the UI
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-latest', // Use Flash for fast, low-cost OCR
    contents: [
      {
        parts: [
          { inlineData: { mimeType, data: base64Data } },
          { text: "Transcribe all legible text from this image exactly as it appears. Do not summarize, just output the text content." }
        ]
      }
    ]
  });

  if (!response.text) {
      throw new Error("No text identified in image.");
  }
  return response.text;
};

export const generateExam = async (
  loFiles: UploadedFile[],
  blueprint: BlueprintSection[],
  questionCount: number = 10,
  difficulty: DifficultyLevel = 'standard',
  referenceTotalQuestions: number = 40
): Promise<ExamQuestion[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Prepare LO Context
  let loContext = "";
  if (loFiles.length > 0) {
      loFiles.forEach(f => {
        loContext += `\n--- START OF LEARNING OBJECTIVE FILE: ${f.name} ---\n${f.content}\n--- END OF LEARNING OBJECTIVE FILE: ${f.name} ---\n`;
      });
  } else {
      loContext = "No Learning Objectives provided.";
  }

  // Prepare Blueprint Context (Iterate through buckets)
  let blueprintContext = "";
  blueprint.forEach((section) => {
      // Calculate or Pass raw info
      blueprintContext += `\n\n=== SECTION: ${section.title} ===\n`;
      blueprintContext += `Reference Question Count (from original blueprint): ${section.questionCount} (based on a ${referenceTotalQuestions}-question exam)\n`;
      blueprintContext += `Context/Description: ${section.description}\n`;

      if (section.files.length > 0) {
          section.files.forEach(f => {
              blueprintContext += `\n--- FILE (${section.title}): ${f.name} ---\n${f.content}\n--- END FILE ---\n`;
          });
      } else {
          blueprintContext += `(No files uploaded for this section)\n`;
      }
  });

  // Define Difficulty Logic
  let difficultyInstruction = "";
  if (difficulty === 'standard') {
    difficultyInstruction = `
    **DIFFICULTY: STANDARD**
    - Questions should be straightforward clinical scenarios.
    - Distractors should be plausible but clearly incorrect to a well-studied student.
    - Focus on 'most likely diagnosis' and 'initial management'.
    `;
  } else if (difficulty === 'hard') {
    difficultyInstruction = `
    **DIFFICULTY: HARD**
    - **Distractor Quality:** Distractors MUST be "homogeneous". e.g., if the answer is an antibiotic, all distractors must be antibiotics of the same class or used for similar conditions. NO "outlier" answers.
    - **Vignette:** Include minor "red herrings" or distracting details that might lead to a common trap.
    - **Ambiguity:** Scenarios should require ruling out a very close differential diagnosis.
    `;
  } else if (difficulty === 'expert') {
    difficultyInstruction = `
    **DIFFICULTY: EXPERT / MASTER**
    - **Best Next Step:** Focus heavily on "What is the BEST next step". Provide 3 options that are *correct* steps, but only ONE is the immediate priority.
    - **Nuance:** Test specific contraindications, timeline-dependent decisions, or subtle side effects.
    - **Misconceptions:** Specifically target common student misconceptions.
    - **No Giveaways:** Ensure the correct answer is NOT the longest option or the only one with specific detail.
    `;
  }

  const prompt = `
    Based on the attached files, generate a Practice Exam.

    **SCALING INSTRUCTIONS:**
    The user wants to generate exactly **${questionCount}** questions.
    The provided Blueprint sections are based on a reference total of **${referenceTotalQuestions}** questions.
    You must SCALE the number of questions for each section proportionally.

    *Example:* If a section has "10-12" questions in a 40-question reference exam, and the user asks for 10 questions (1/4th the size), that section should have roughly 2-3 questions in this output.

    **Constraint Checklist & Confidence Score:**
    1. Generate exactly ${questionCount} questions? Yes.
    2. Proportional Scaling? Yes.
    3. Output strictly valid JSON? Yes.

    ${difficultyInstruction}

    **PART 1: Global Learning Objectives (LOs)**
    Use these to determine *what* to test across all sections.
    ${loContext}

    **PART 2: Exam Blueprint & Content**
    ${blueprintContext}
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION_BASE,
        thinkingConfig: {
            thinkingBudget: 4096, 
        },
        maxOutputTokens: 32768,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            exam: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.INTEGER },
                  vignette: { type: Type.STRING },
                  leadIn: { type: Type.STRING },
                  options: {
                    type: Type.OBJECT,
                    properties: {
                      A: { type: Type.STRING },
                      B: { type: Type.STRING },
                      C: { type: Type.STRING },
                      D: { type: Type.STRING },
                    },
                    required: ["A", "B", "C", "D"],
                  },
                  correctAnswer: { type: Type.STRING, enum: ["A", "B", "C", "D"] },
                  explanation: { type: Type.STRING },
                  metadata: {
                    type: Type.OBJECT,
                    properties: {
                      losTested: { type: Type.ARRAY, items: { type: Type.STRING } },
                      cluster: { type: Type.STRING },
                      cognitiveLevel: { type: Type.STRING },
                      subtype: { type: Type.STRING },
                      week: { type: Type.INTEGER },
                    },
                  },
                },
                required: ["id", "vignette", "leadIn", "options", "correctAnswer", "explanation", "metadata"],
              },
            },
          },
        },
      },
    });

    if (response.text) {
      // Sanitize response
      let cleanText = response.text.replace(/```json/g, '').replace(/```/g, '').trim();

      const parsed = JSON.parse(cleanText);
      if (parsed.exam && Array.isArray(parsed.exam)) {
        return parsed.exam;
      }
    }
    throw new Error("Invalid response format from AI");
  } catch (error) {
    console.error("Gemini API Error:", error);

    if (error instanceof SyntaxError) {
      throw new Error("The AI response was incomplete. Try reducing question count or simplifying the input.");
    }

    const errorMessage = error instanceof Error ? error.message : String(error);

    // Map common errors
    if (errorMessage.includes("403") || errorMessage.includes("PERMISSION_DENIED")) {
        throw new Error("Access Denied: Invalid API Key.");
    }
    if (errorMessage.includes("429") || errorMessage.includes("RESOURCE_EXHAUSTED")) {
        throw new Error("Rate Limit Exceeded: Please wait a moment.");
    }
    if (errorMessage.includes("503") || errorMessage.includes("UNAVAILABLE")) {
        throw new Error("Model Overloaded: Please try again shortly.");
    }

    throw error;
  }
};

import { UploadedFile } from '../types';
import { extractTextFromImage } from './geminiService';

declare const pdfjsLib: any;
declare const mammoth: any;
declare const XLSX: any;
declare const JSZip: any;

export const readFileContent = async (file: File): Promise<UploadedFile> => {
  const fileExtension = file.name.split('.').pop()?.toLowerCase();
  let content = '';
  let type: 'pdf' | 'docx' | 'txt' | 'xlsx' | 'pptx' | 'image' = 'txt';

  // We do NOT wrap this in try/catch. We want the error to bubble up to the component.
  if (fileExtension === 'pdf') {
    type = 'pdf';
    content = await readPdf(file);
  } else if (fileExtension === 'docx') {
    type = 'docx';
    content = await readDocx(file);
  } else if (fileExtension === 'xlsx') {
    type = 'xlsx';
    content = await readXlsx(file);
  } else if (fileExtension === 'pptx') {
    type = 'pptx';
    content = await readPptx(file);
  } else if (['png', 'jpg', 'jpeg', 'webp', 'heic'].includes(fileExtension || '')) {
    type = 'image';
    content = await readImage(file);
  } else {
    content = await file.text();
  }

  return {
    id: crypto.randomUUID(),
    name: file.name,
    type,
    content,
    size: file.size,
  };
};

const readImage = async (file: File): Promise<string> => {
    // 1. Convert to Base64
    const base64Data = await new Promise<string>((resolve, reject) => {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = () => resolve(reader.result as string);
        reader.onerror = error => reject(error);
    });

    // 2. Strip the Data URL prefix (e.g. "data:image/png;base64,")
    const rawBase64 = base64Data.split(',')[1];

    // 3. Send to Gemini for OCR
    return await extractTextFromImage(rawBase64, file.type);
};

const readPdf = async (file: File): Promise<string> => {
  const arrayBuffer = await file.arrayBuffer();
  const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
  let text = '';

  for (let i = 1; i <= pdf.numPages; i++) {
    const page = await pdf.getPage(i);
    const content = await page.getTextContent();
    const strings = content.items.map((item: any) => item.str);
    text += strings.join(' ') + '\n';
  }
  return text;
};

const readDocx = async (file: File): Promise<string> => {
  const arrayBuffer = await file.arrayBuffer();
  const result = await mammoth.extractRawText({ arrayBuffer: arrayBuffer });
  return result.value;
};

const readXlsx = async (file: File): Promise<string> => {
  const arrayBuffer = await file.arrayBuffer();
  const workbook = XLSX.read(arrayBuffer);
  let text = '';

  workbook.SheetNames.forEach((sheetName: string) => {
    const worksheet = workbook.Sheets[sheetName];
    // sheet_to_txt extracts tab-separated values, effectively converting the sheet to a readable text format
    const sheetText = XLSX.utils.sheet_to_txt(worksheet);
    if (sheetText.trim().length > 0) {
      text += `--- Sheet: ${sheetName} ---\n${sheetText}\n\n`;
    }
  });
  return text;
};

const readPptx = async (file: File): Promise<string> => {
  const arrayBuffer = await file.arrayBuffer();
  const zip = await new JSZip().loadAsync(arrayBuffer);
  const slideFiles: any[] = [];

  zip.forEach((relativePath: string, zipEntry: any) => {
    // Look for slide XML files in ppt/slides/
    if (relativePath.match(/^ppt\/slides\/slide\d+\.xml$/)) {
        slideFiles.push(zipEntry);
    }
  });

  // Sort by slide number (slide1.xml, slide2.xml...)
  slideFiles.sort((a, b) => {
      const matchA = a.name.match(/slide(\d+)\.xml/);
      const matchB = b.name.match(/slide(\d+)\.xml/);
      const numA = matchA ? parseInt(matchA[1]) : 0;
      const numB = matchB ? parseInt(matchB[1]) : 0;
      return numA - numB;
  });

  let text = "";
  for (const slide of slideFiles) {
      const content = await slide.async("string");
      // Extract text within <a:t> tags
      const slideTexts = content.match(/<a:t>(.*?)<\/a:t>/g);

      if (slideTexts) {
         const cleanText = slideTexts.map((t: string) => t.replace(/<\/?a:t>/g, '')).join(' ');
         const slideNum = slide.name.match(/slide(\d+)\.xml/)[1];
         if (cleanText.trim()) {
            text += `\n--- Slide ${slideNum} ---\n${cleanText}\n`;
         }
      }
  }
  return text;
};

import React, { useCallback, useState } from 'react';
import { Upload, X, FileText, FileType, FileSpreadsheet, Presentation, Image as ImageIcon, Loader2, AlertCircle } from 'lucide-react';
import { UploadedFile } from '../types';
import { readFileContent } from '../services/fileService';

interface FileUploadProps {
  id: string;
  files: UploadedFile[];
  onFilesChanged: (files: UploadedFile[]) => void;
  title?: string;
  description?: string;
  className?: string;
}

interface ProcessingFile {
    id: string;
    file: File;
    status: 'processing' | 'error';
    error?: string;
}

const FileUpload: React.FC<FileUploadProps> = ({ 
  id, 
  files, 
  onFilesChanged, 
  title = "Upload Files", 
  description = "PDF, DOCX, PPTX, XLSX, TXT or Images (Screenshot/Photo)",
  className = ""
}) => {
  // We keep a separate list for files currently processing or failed.
  // Successful files move to 'files' prop.
  const [processingFiles, setProcessingFiles] = useState<ProcessingFile[]>([]);

  const processFiles = async (newFiles: File[]) => {
      if (newFiles.length === 0) return;

      // 1. Create temporary entries
      const newProcessingItems: ProcessingFile[] = newFiles.map(f => ({
          id: crypto.randomUUID(),
          file: f,
          status: 'processing'
      }));

      setProcessingFiles(prev => [...prev, ...newProcessingItems]);

      // 2. Process each file
      const successfullyProcessed: UploadedFile[] = [];

      // We process concurrently but update state individually
      await Promise.all(newProcessingItems.map(async (item) => {
          try {
              const result = await readFileContent(item.file);
              successfullyProcessed.push(result);

              // Remove from processing list upon success
              setProcessingFiles(prev => prev.filter(p => p.id !== item.id));
          } catch (error: any) {
              // Update status to error
              setProcessingFiles(prev => prev.map(p => 
                  p.id === item.id 
                  ? { ...p, status: 'error', error: error.message || "Failed to parse file" } 
                  : p
              ));
          }
      }));

      // 3. Update parent with successful files
      if (successfullyProcessed.length > 0) {
          onFilesChanged([...files, ...successfullyProcessed]);
      }
  };

  const handleDrop = useCallback(
    async (e: React.DragEvent<HTMLDivElement>) => {
      e.preventDefault();
      e.stopPropagation();
      const droppedFiles = Array.from(e.dataTransfer.files) as File[];
      await processFiles(droppedFiles);
    },
    [files, onFilesChanged]
  );

  const handleFileInput = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const selectedFiles = Array.from(e.target.files) as File[];
      await processFiles(selectedFiles);
      e.target.value = ''; // Reset input
    }
  };

  const removeFile = (fileId: string) => {
    onFilesChanged(files.filter((f) => f.id !== fileId));
  };

  const removeProcessingFile = (tempId: string) => {
      setProcessingFiles(prev => prev.filter(p => p.id !== tempId));
  };

  const getIcon = (type: string) => {
    if (type === 'pdf') return <FileType className="w-5 h-5 text-red-500" />;
    if (type === 'docx') return <FileType className="w-5 h-5 text-blue-500" />;
    if (type === 'xlsx') return <FileSpreadsheet className="w-5 h-5 text-green-600" />;
    if (type === 'pptx') return <Presentation className="w-5 h-5 text-orange-500" />;
    if (type === 'image') return <ImageIcon className="w-5 h-5 text-purple-500" />;
    return <FileText className="w-5 h-5 text-slate-500" />;
  };

  return (
    <div className={`w-full space-y-4 ${className}`}>
      <label className="block text-sm font-medium text-slate-700 mb-2">
        {title}
      </label>
      <div
        onDragOver={(e) => e.preventDefault()}
        onDrop={handleDrop}
        className="border-2 border-dashed border-slate-300 rounded-lg p-6 text-center transition-colors cursor-pointer bg-slate-50/50 relative overflow-hidden hover:bg-slate-50"
        onClick={() => document.getElementById(id)?.click()}
      >
        <input
          type="file"
          id={id}
          multiple
          accept=".pdf,.docx,.txt,.xlsx,.pptx,.png,.jpg,.jpeg,.webp,.heic"
          className="hidden"
          onChange={handleFileInput}
        />

        <div className="flex flex-col items-center justify-center space-y-2">
            <div className="p-3 bg-white border border-slate-200 rounded-full shadow-sm">
                <Upload className="w-5 h-5 text-blue-600" />
            </div>
            <p className="text-sm font-medium text-slate-900">
                Click to upload or drag and drop
            </p>
            <p className="text-xs text-slate-500">
                {description}
            </p>
        </div>
      </div>

      <div className="space-y-2">
          {/* List Processing/Error Files */}
          {processingFiles.map((item) => (
              <div
                key={item.id}
                className={`flex items-center justify-between p-3 border rounded-md shadow-sm transition-all ${item.status === 'error' ? 'bg-red-50 border-red-200' : 'bg-white border-blue-200'}`}
              >
                  <div className="flex items-center space-x-3 overflow-hidden w-full">
                      <div className="flex-shrink-0">
                          {item.status === 'processing' ? (
                              <Loader2 className="w-5 h-5 text-blue-600 animate-spin" />
                          ) : (
                              <AlertCircle className="w-5 h-5 text-red-500" />
                          )}
                      </div>
                      <div className="min-w-0 flex-1">
                          <p className={`text-sm font-medium truncate ${item.status === 'error' ? 'text-red-700' : 'text-slate-700'}`}>
                              {item.file.name}
                          </p>
                          <p className="text-xs text-slate-400">
                              {item.status === 'processing' ? 'Extracting text...' : item.error}
                          </p>
                          {/* Progress Bar for processing */}
                          {item.status === 'processing' && (
                              <div className="w-full bg-slate-100 rounded-full h-1 mt-1.5 overflow-hidden">
                                  <div className="bg-blue-600 h-1 rounded-full animate-progress-indeterminate"></div>
                              </div>
                          )}
                      </div>
                  </div>
                  {item.status === 'error' && (
                       <button
                       type="button"
                       onClick={(e) => {
                         e.stopPropagation();
                         removeProcessingFile(item.id);
                       }}
                       className="ml-2 p-2 hover:bg-red-200 rounded-full transition-colors text-red-400 hover:text-red-700 flex-shrink-0"
                     >
                       <X className="w-4 h-4" />
                     </button>
                  )}
              </div>
          ))}

          {/* List Successfully Uploaded Files */}
          {files.map((file) => (
            <div
              key={file.id}
              className="flex items-center justify-between p-3 bg-white border border-slate-200 rounded-md shadow-sm hover:shadow-md transition-shadow"
            >
              <div className="flex items-center space-x-3 overflow-hidden">
                <div className="flex-shrink-0">
                  {getIcon(file.type)}
                </div>
                <div className="min-w-0">
                  <p className="text-sm font-medium text-slate-700 truncate">
                    {file.name}
                  </p>
                  <p className="text-xs text-slate-400">
                    {(file.size / 1024).toFixed(0)} KB {file.type === 'image' && '(OCR Extracted)'}
                  </p>
                </div>
              </div>
              <button
                type="button"
                onClick={(e) => {
                  e.stopPropagation();
                  removeFile(file.id);
                }}
                className="ml-2 p-2 hover:bg-red-100 rounded-full transition-colors text-slate-400 hover:text-red-600 flex-shrink-0 focus:outline-none focus:ring-2 focus:ring-red-500"
                aria-label="Remove file"
              >
                <X className="w-5 h-5" />
              </button>
            </div>
          ))}
      </div>
    </div>
  );
};

